<script lang="ts">
    import type { Snippet } from "svelte";
    import type { AppFile } from "../../util/interfaces";
    import { formatDate, formatSize, isAppFileFolder } from "../../util/util.svelte";
    import { Style } from "../../data/styles";
    import ItemsPanel from "./ItemsPanelComp.svelte";
    import ButtonComp from "../ButtonComp.svelte";

    let
    {
        items,
        onItemPicked,
        header,
        footer,
    }:
    {
        items: AppFile[]
        onItemPicked: (item: AppFile, index: number) => void
        header?: Snippet
        footer?: Snippet
    } = $props()
</script>

