    header={header}
    footer={footer}
    items={items}
    onItemPicked={onItemPicked}
>
    {#snippet itemSnippet(file: AppFile, index: number)}
        <ButtonComp
            width="100%"
            index={index}
            >
            {#snippet contentSnippet()}
                <div class="row"
                    style:font-size={Style.DEFAULT.get("fontSize")}
                    >
                    <div class="col">{isAppFileFolder(file) ? "📁" : "📄"}</div>
                    <div class="col">{file.name}</div>
                    <div class="col">{isAppFileFolder(file) ? "Folder" : formatSize(parseFloat(file.size))}</div>
                    <div class="col">{formatDate(new Date(file.modifiedTime))}</div>
                </div>
            {/snippet}
        </ButtonComp>
    {/snippet}
</ItemsPanel>

