let touchButton = 0
let singleTouchLongPressTimeout: number = -1

function onWorldTouchStart(e: TouchEvent)
{
    wasPinching = false

    touchButton = 2

    touchCount = e.touches.length

    if(touchCount == 1)
    {
        const touch = e.touches[0]

        const touchStartPos = { x: touch.clientX, y: touch.clientY }

        singleTouchLongPressTimeout = setTimeout(() =>
        {
            const distanceFromStartSq = distanceSq(touchStartPos, pointerLast)

            if(distanceFromStartSq < 200)
            {
                const [node, depth, els] = getEventTargetNode(e)

                if(node != null)
                {
                    if(tryStartDraggingNodes(node))
                    {
                        touchButton = 0
                        setPointerStateToPressed(touchButton)
                    }
                }
            }
        }, 500)

        const [node, depth, els] = getEventTargetNode(e)

        if(node == null)
        {
            if(depth == 1)
            {
                touchButton = 2
            }
        }
    }

    // if(VISUALIZE_TOUCH)
    // {
    //     debugTouch(e, "onWorldTouchStart")
    // }

    handleWorldPointerDown(e, touchPos.x, touchPos.y, touchButton)
}

