function setPointerStateToPressed(button: number)
{
    for(let i = 0; i < pointerStates.length; i++)
    {
        pointerStates[i] = i == button
    }
}

function handleWorldPointerDown(e: UIEvent, x: number, y: number, button: number)
{
    clickDownMs[button] = Date.now()
    pointerStates[button] = true

    pointerLastDown.x = x
    pointerLastDown.y = y

    // log(`pointerLast updated: ${softToFixed(pointerLast.x)}, ${softToFixed(pointerLast.y)}`)

    const tab = get(currentTab)
    const camera = tab.camera

    // camera.setPosition(0, 0, false)
    // camera.setZoom(1)

    const [node, depth, els] = getEventTargetNode(e)

    if(node != null)
    {
    //     console.log(depth)
    //     node.printDebugInfo()

        // setDebugText("clicked node", posToString(node.pos))
    }

    const clickedEl = els[0]

    if(!shouldSelectParentNodeOnElClick(clickedEl))
    {
        return
    }

    // messages.addDebugMessage(`root mouse down: ${button} | node: ${node != null ? node.id : "null"}`)
    
    switch(button)
    {
        case 0:
        {
            lastPointerDownPos.x = lastPointerDownWorldPos.x = x
            lastPointerDownPos.y = lastPointerDownWorldPos.y = y

            translatePosToWorldPos(lastPointerDownWorldPos)

            triedDraggingNodesThisDrag = false

            let startDraggingSelectionBox = node == null

            if(startDraggingSelectionBox)
            {
                const clearSelection = noModifiersHeld(0, 1)

                if(clearSelection)
                {
                    tab.deselectNodes()
                }
                else
                {
                    selectionBoxDraggingStartSelectedNodes = new Set(tab.selectedNodes)
                }

                selectionBoxStartWorldPos.x = selectionBoxPos1.x = selectionBoxPos2.x = lastPointerDownWorldPos.x
                selectionBoxStartWorldPos.y = selectionBoxPos1.y = selectionBoxPos2.y = lastPointerDownWorldPos.y

                console.log(`selectionBoxStartWorldPos.y set to ${selectionBoxStartWorldPos.y} on pointerDown`)

                // setDebugCircle("selectionBoxDragWorldStartPos", selectionBoxDragWorldStartPos, "magenta")

                selectionBoxDragging = true
            }
        }
        break

        case 1:
            // for(const node of tab.nodes)
            // {
            //     if(!node.alive)
            //     {
            //         continue
            //     }

            // }

            // if(tab != null)
            // {
            //     camera.centerToNode(tab.rootNode)
            // }
            // else
            // {
            //     camera.resetPositionAndZoom()
            // }
            break
            
        case 2:
            break
    }
}

//region onMouseUp
function onWorldTouchEnd(e: TouchEvent)
{
    clearTimeout(singleTouchLongPressTimeout)

