function handlePointerUp(e: UIEvent, button: number)
{
    const tab = get(currentTab)
    // const node = getMouseEventTargetNode(e)

    pointerStates[button] = false
    // console.log('root mouse up', e.button)

    switch(button)
    {
        case 0:
        {
            if(selectionBoxDragging)
            {
                selectionBoxDragging = false
                selectionBoxDraggingStartSelectedNodes.clear()
    
                console.log(`Selected ${tab.selectedNodes.size} nodes!`)
            }
            else if(dragToNode != null)
            {
                const stealingIdentityOfNode = dragToNode.mimicOf ?? dragToNode.identityTheftTarget

                if(stealingIdentityOfNode != null)
                {
                    dragToNode = stealingIdentityOfNode
                }

                let attachNode: (node: Node) => MultiNodedAction

                let childIndex = dragToNode.childIndex

                switch(dragToNodeDirection)
                {
                    case Direction2D4.Up:
                    case Direction2D4.Down:
                    {
                        const up = dragToNodeDirection == Direction2D4.Up

                        attachNode = node =>
                        {
                            return node.attachToParent(dragToNode.parent, childIndex++ + (up ? 0 : 1), false)
                        }
                    }
                    break

                    case Direction2D4.Right:
                    {
                        attachNode = node =>
                        {
                            return node.attachToParent(dragToNode, undefined, false)
                        }
                    }
                    break

                    default:
                    {
                        throw new Error("Invalid dragToNodeDirection: " + dragToNodeDirection)
                    }
                    break
                }

                const actions: NodedAction[] = []

                const sortedDragingNodes = [...draggingNodes].sort((a, b) => a.getWorldRect().y - b.getWorldRect().y)

                for(let node of sortedDragingNodes)
                {
                    const stealingIdentityOfNode = node.mimicOf ?? node.identityTheftTarget

                    if(stealingIdentityOfNode != null)
                    {
                        node = stealingIdentityOfNode
                    }

                    actions.push(attachNode(node))
                }

                addActionToHistory(actions)

                dragToNode.updateTreeRecursive()
            }
            else
            {
                const [node, depth, els] = getEventTargetNode(e)

                if(node != null)
                {
                    const distanceMovedSq = distanceSq(pointerLastDown, pointerLast)

                    // tab.camera.centerToNode(node)

                    // const shouldDeselect = 50 < distanceMovedSq
                    const shouldDeselect = true
    
                    //Shift select
                    if
                    (
                        modifierStates[1] &&
                        tab.lastSelectedNode != null &&
                        tab.lastSelectedNode !== node &&
                        tab.lastSelectedNode.parent == node.parent
                    )
                    {
                        const deselectNodes = !modifierStates[0]
    
                        if(deselectNodes)
                        {
                            tab.deselectNodes()
                        }
    
                        const lastSelectedNodeIndex = tab.lastSelectedNode.childIndex
                        const nodeIndex = node.childIndex
    
                        const from = Math.min(lastSelectedNodeIndex, nodeIndex)
                        const to = Math.max(lastSelectedNodeIndex, nodeIndex)
    
                        for(let i = from; i <= to; i++)
                        {
                            tab.selectNodes(node.parent.children[i], false)
                        }
                    }
                    else if(modifierStates[0] || modifierStates[1])
                    {
                        if(tab.selectedNodes.has(node))
                        {
                            tab.deselectNodes(node)
                        }
                        else
                        {
                            tab.selectNodes(node, false)
                        }
                    }
                    else
                    {
                        if(node.selected)
                        {
                            if(masterDraggingNode == null)
                            {
                                if(shouldDeselect)
                                {
                                    const nodesToDeselect: Set<Node> = new Set(tab.selectedNodes)
            
                                    nodesToDeselect.delete(node)
            
                                    tab.deselectNodes(nodesToDeselect)
                                }
                            }
                        }
                        else
                        {
                            tab.selectNodes(node, true)
                        }
                    }
                }
            }

            if(tab.lastSelectedNode != null)
            {
                if(!tab.lastSelectedNode.isRoot)
                {
                    tab.lastSelectedNode.parent.updateChildren()
                }
            }
        }
        break

        case 1:
        {

        }
        break

        case 2:
        {

        }
        break
    }

    if(draggingNodes.size > 0)
    {
        stopDraggingNodes()
    }
}

function stopDraggingNodes()
{
    cancelNodeDragPreview()

    for(const node of draggingNodes)
    {
        if(node.parent != null)
        {
            node.parent.updateChildren()
        }
    }

    draggingNodes.clear()
    wasDraggingNodes = false
    masterDraggingNode = null!
}

