function onWorldMouseWheel(e: WheelEvent)
{
    const direction = getMouseWheelEventDirection(e)
    // messages.addDebugMessage(`mouse wheel: deltaY: ${e.deltaY} | ${Direction2D4[direction]}`)

    const [node, depth, els] = getEventTargetNode(e)

    if(els.length > 0)
    {
        handleScroll(direction, direction == Direction2D4.Up ? 1.1 : 0.9)
    }

    // e.preventDefault()
    // e.stopPropagation()
}

function handleScroll(direction: Direction2D4, zoomScale: number, zoomCenter: Pos = pointerWorldLast)
{
    const tab = get(currentTab)
    const camera = tab.camera

    if(camera == null)
    {
        messages.addErrorMessage("Camera is null in handleScroll")
    }

    switch(direction)
    {
        case Direction2D4.Up:
            camera.scaleZoom(zoomScale, zoomCenter, false)
            break

        case Direction2D4.Down:
            camera.scaleZoom(zoomScale, zoomCenter, false)
            break

        case Direction2D4.Left:
            camera.offsetPosition(-userConfig.get("SCROLL_SIDE_MOVE_SPEED"), 0, 0, false)
            break

        case Direction2D4.Right:
            camera.offsetPosition(userConfig.get("SCROLL_SIDE_MOVE_SPEED"), 0, 0, false)
            break
    }
}

