//region onTouchMove
let lastTouchDistanceFromCenter = 0

let touchCount = 0
let wasPinching = false

function onWorldTouchMove(e: TouchEvent)
{
    if(touchCount != e.touches.length)
    {
        onWorldTouchStart(e)
    }

    let shouldPan = false
    
    if(e.touches.length == 1)
    {
        shouldPan = true
    }
    if(e.touches.length >= 2)
    {
        shouldPan = true

        // log(`centerPos: ${centerPos.x}, ${centerPos.y} | lastMultiTouchPos: ${lastMultiTouchPos.x}, ${lastMultiTouchPos.y}`)

        const touchDistanceFromCenterSq = distanceSqRaw(e.touches[0].clientX, e.touches[0].clientY, touchPos.x, touchPos.y)

        if(touchDistanceFromCenterSq != 0)
        {
            const thisDistance = Math.sqrt(touchDistanceFromCenterSq)
            if(!wasPinching)
            {
                wasPinching = true
                lastTouchDistanceFromCenter = thisDistance
            }
            const distanceChange = thisDistance - lastTouchDistanceFromCenter
    
            if(distanceChange != 0)
            {
                const zoomScale = 1 + distanceChange / 150
        
                const direction = distanceChange > 0 ? Direction2D4.Up : Direction2D4.Down
        
                // log(Direction2D4[direction])
                // log(`${softToFixed(zoomScale)}`)
        
                handleScroll(direction, zoomScale, touchWorldPos)
        
                lastTouchDistanceFromCenter = thisDistance
            }
        }
    }

    if(shouldPan)
    {
        handleWorldPointerMove(e, touchPos.x, touchPos.y)
    }

    // if(VISUALIZE_TOUCH)
    // {
    //     debugTouch(e)
    // }
}

//region onMouseMove
function onWorldMouseMove(e: MouseEvent)
{
    handleWorldPointerMove(e, e.clientX, e.clientY)
}

function handleWorldPointerMove(e: UIEvent, x: number, y: number)
{
    const tab = get(currentTab)

    if(tab == null)
    {
        return
    }

    const camera = tab.camera

    // setDebugRect("contextMenu", get(contextMenuState).rect, "orange")
    // log(getMaxDistanceFromRect(pointerLast, get(contextMenuState).rect))

    const dx = pointerLast.x - x
    const dy = pointerLast.y - y

    // setDebugText("dx", dx)
    // setDebugText("dy", dy)

    pointerWorldLast.x = x
    pointerWorldLast.y = y

    translatePosToWorldPos(pointerWorldLast, camera)

    if (pointerStates[1] || pointerStates[2])
    {
        camera.offsetPosition(dx, dy, 0, false)
    }
    else if(pointerStates[0])
    {
        if(isTyping())
        {
            return
        }

        if(selectionBoxDragging)
        {
            doSelectionBoxDrag()
        }
        else
        {
            //#region potentially start dragging nodes
            const [node, depth, els] = getEventTargetNode(e)
            if(node != null)
            {
                if(node.isDraggable())
                {
                    if(!triedDraggingNodesThisDrag)
                    {
                        tryStartDraggingNodes(node)
                    }
                }
            }
            //#endregion potentially start dragging nodes
        }

        //#region nodes dragging
        if(masterDraggingNode != null)
        {
            // console.log(`[${draggingNodes.size}] masterDraggingNode: ${masterDraggingNode != null ? masterDraggingNode.id : "null"}`)
            
            draggingNodes.forEach(node =>
            {
                // console.log(`Moving node ${node.id} by dx: ${dx}, dy: ${dy}`)
                node.clearMoveAnimation()
                node.offsetPosition(-dx / camera.centerWorldPos.zoom, -dy / camera.centerWorldPos.zoom, false)
            })
        }

        if(masterDraggingNode != null)
        {
            const distanceDragged = distanceSq(lastPointerDownPos, pointerLast)
    
            if(isWithinDraggingDistanceSq(distanceDragged))
            {
                if(!wasDraggingNodes)
                {
                    wasDraggingNodes = true
                }
    
                const [closestNodeVertical, distanceVertical] = findClosestNodeFromTheirPoint(masterDraggingNode, Direction2D9.Center, Direction2D9.Center, node => node.isDraggable() && !cannotDragToNodes.has(node))
                const [closestNodeHorizontal, distanceHorizontal] = findClosestNodeFromTheirPoint(masterDraggingNode, Direction2D9.Right, Direction2D9.Left, node => node.isDraggable() && !cannotDragToNodes.has(node) && node.children.length == 0)
    
                if(closestNodeHorizontal != null)
                {
                    previewDragToNode(closestNodeHorizontal, false)
                }
    
                if(closestNodeHorizontal == null && closestNodeVertical != null)
                {
                    previewDragToNode(closestNodeVertical, true)
                }
                else if(closestNodeHorizontal != null && closestNodeVertical == null)
                {
                    previewDragToNode(closestNodeHorizontal, false)
                }
                else if(closestNodeHorizontal != null && closestNodeVertical != null)
                {
                    if(distanceVertical < distanceHorizontal)
                    {
                        const closestNodeVerticalTopPos = getRectPoint(closestNodeVertical.getWorldRect(), Direction2D9.Top)
                        const closestNodeVerticalBottomPos = getRectPoint(closestNodeVertical.getWorldRect(), Direction2D9.Bottom)
                        
                        const draggingNodeVerticalTopPos = getRectPoint(masterDraggingNode.getWorldRect(), Direction2D9.Top)
                        const draggingNodeVerticalBottomPos = getRectPoint(masterDraggingNode.getWorldRect(), Direction2D9.Bottom)

                        if(VISUALIZE_NODE_DRAG)
                        {
                            setDebugCircle("closestNodeVerticalTopPos", closestNodeVerticalTopPos, "green")
                            setDebugCircle("closestNodeVerticalBottomPos", closestNodeVerticalBottomPos, "green")
    
                            setDebugCircle("draggingNodeVerticalTopPos", draggingNodeVerticalTopPos, "blue")
                            setDebugCircle("draggingNodeVerticalBottomPos", draggingNodeVerticalBottomPos, "blue")
                        }
    
                        const closestNodeShortestVerticalDistance = Math.min(distanceSq(draggingNodeVerticalBottomPos, closestNodeVerticalTopPos), distanceSq(draggingNodeVerticalTopPos, closestNodeVerticalBottomPos))
    
                        if(closestNodeShortestVerticalDistance < distanceHorizontal)
                        {
                            previewDragToNode(closestNodeVertical, true)
                            
                        }
                        else
                        {
                            previewDragToNode(closestNodeHorizontal, true)
                        }
                    }
                    else
                    {
                        previewDragToNode(closestNodeHorizontal, false)
                    }
                }
                else
                {
                    cancelNodeDragPreview()
                }
            }
            else
            {
                cancelNodeDragPreview()
            }
        }
        //#region nodes dragging
    }
}

function tryStartDraggingNodes(node: Node): boolean
{
    if(!node.isDraggable())
    {
        return false
    }

    const tab = get(currentTab)

    let nodes: Node[]

    if(node.selected)
    {
        nodes = tab.selectedNodesArray.filter(node => node.isDraggable())
    }
    else
    {
        nodes = [node]
    }

    if(nodes.length == 0)
    {
        return false
    }

    let nodeIsChildOfOtherDraggingNode = false

    if(nodes.length > 1)
    {
        for(const draggingNode of nodes)
        {
            draggingNode.forEachChildRecursive(child =>
            {
                if(node == child)
                {
                    nodeIsChildOfOtherDraggingNode = true
                    
                    return ForAction.Break
                }
            })
        }
    
        // log(`nodeIsChildOfOtherDraggingNode: ${nodeIsChildOfOtherDraggingNode}`)
        draggingNodes = nodeIsChildOfOtherDraggingNode ? new Set([node]) : new Set(nodes)
    }

    draggingNodes.add(node)
    cannotDragToNodes = new Set()
    cannotDragToNodes.add(node)

    for(const node of draggingNodes)
    {
        node.forEachChildRecursive(child =>
        {
            //Do not double drag
            draggingNodes.delete(child)
            //Do not attach to children
            cannotDragToNodes.add(child)
        })
        //Do not attach to self
        cannotDragToNodes.add(node)
    }

    for(const node of cannotDragToNodes)
    {
        if(node.mimicOf != null)
        {
            cannotDragToNodes.add(node.mimicOf)
        }

        for(const mimic of node.mimickedBy.values())
        {
            cannotDragToNodes.add(mimic)
        }
    }

    // #region cannotDragToNodes done

    const success = draggingNodes.has(node)

    if(success)
    {
        // log("Start")
        masterDraggingNode = node
    }
    else
    {
        // log("Abort")
        stopDraggingNodes()
    }

    // log(`Cannot drag to nodes:`)
    // log(cannotDragToNodes)

    triedDraggingNodesThisDrag = true

    return success
}

export function raycastWorld(viewportOriginPos: Pos, direction: Pos, onStep: (matches: HTMLElement[], pos: Pos, step: number, distance: number) => boolean, stepSize: number, maxDistance: number = Infinity)
{
    let step = 0
    let distance = 0

    direction = normalizeVec2(direction)

    while(distance < maxDistance)
    {
        const viewportPos =
        {
            x: viewportOriginPos.x + direction.x * distance,
            y: viewportOriginPos.y + direction.y * distance,
        }

        // setDebugCircle(`raycastGridPos ${step}`, viewportPos, hslToRgbString(step * 15, 0.5, 0.5))

        if(!isWithinRange(viewportPos.x, 0, window.innerWidth) || !isWithinRange(viewportPos.y, 0, window.innerHeight))
        {
            return false
        }

        const elements = document.elementsFromPoint(viewportPos.x, viewportPos.y)
        const htmlElements: HTMLElement[] = elements.filter(el => el instanceof HTMLElement) as HTMLElement[]

        const stop = onStep(htmlElements, viewportPos, distance / stepSize, distance)

        if(stop)
        {
            return true
        }

        distance += stepSize
        step++
    }
}

export function raycastWorldForNodes(viewportOriginPos: Pos, direction: Pos, onStep: (node: Node, pos: Pos, step: number, distance: number) => boolean, stepSize: number = projectConfig.get("NODE_MIN_HEIGHT"), maxDistance: number = Infinity)
{
    return raycastWorld(viewportOriginPos, direction, (elements, pos, step, distance) =>
    {
        for(const el of elements)
        {
            const node = getNodeFromHTMLElement(el, false)[0]

            if(node != null)
            {
                const stop = onStep(node, pos, step, distance)

                if(stop)
                {
                    return true
                }
            }
        }

        return false
    }, stepSize, maxDistance)
}

function doSelectionBoxDrag()
{
    if(!selectionBoxDragging)
    {
        return
    }

    if(distanceSqRaw(selectionBoxStartWorldPos.x, selectionBoxStartWorldPos.y, pointerWorldLast.x, pointerWorldLast.y) < 25 ** 2)
    {
        return
    }

    selectionBoxPos1.x = Math.min(selectionBoxStartWorldPos.x, pointerWorldLast.x)
    selectionBoxPos1.y = Math.min(selectionBoxStartWorldPos.y, pointerWorldLast.y)
    selectionBoxPos2.x = Math.max(selectionBoxStartWorldPos.x, pointerWorldLast.x)
    selectionBoxPos2.y = Math.max(selectionBoxStartWorldPos.y, pointerWorldLast.y)

    const tab = get(currentTab)

    if(modifierStates[0] && modifierStates[1])
    {
        //invert
        selectionBoxDraggingSelectionMode = SelectionMode.Invert
    }
    else if(modifierStates[1])
    {
        //remove
        selectionBoxDraggingSelectionMode = SelectionMode.Remove
    }
    else if(modifierStates[0])
    {
        //add
        selectionBoxDraggingSelectionMode = SelectionMode.Add
    }

    const useSavedSelectedNodes = selectionBoxDraggingSelectionMode != SelectionMode.Set
    const nodesToSelect: Set<Node> = selectionBoxDraggingNodesToSelect

    nodesToSelect.clear()

    if(useSavedSelectedNodes)
    {
        addAllFromTo(selectionBoxDraggingStartSelectedNodes, nodesToSelect)
    }

    const nodes = tab.nodes
    
    for(const node of nodes)
    {
        if(node.worldPositionsOverlapping(selectionBoxPos1, selectionBoxPos2))
        {
            switch(selectionBoxDraggingSelectionMode)
            {
                case SelectionMode.Set:
                case SelectionMode.Add:
                    nodesToSelect.add(node)
                    break

                case SelectionMode.Remove:
                    nodesToSelect.delete(node)
                    break

                case SelectionMode.Invert:
                if(nodesToSelect.has(node))
                {
                    nodesToSelect.delete(node)
                }
                else
                {
                    nodesToSelect.add(node)
                }
                break
            }
        }
    }

    tab.selectNodes(nodesToSelect, true)
}

function previewDragToNode(draggedToNode: Node, verticalOrHorizontal: boolean)
{
    const draggedToNodeCenter = draggedToNode.getWorldCenter()

    // setDebugCircle("draggedToNodeCenter", draggedToNodeCenter, draggedToNode.getBackgroundColor())

    let i = 0

    for(const draggingNode of draggingNodes)
    {
        const draggingNodeCenter = draggingNode.getWorldCenter()

        // setDebugCircle(`draggingNodeCenter_${i}`, draggingNodeCenter, draggingNode.getBackgroundColor())
        i++
    
        if(verticalOrHorizontal)
        {
            draggingNode.lineToParentNode = draggedToNode.parent
        }
        else
        {
            draggingNode.lineToParentNode = draggedToNode
        }
    
        dragToNode = draggedToNode
        if(verticalOrHorizontal)
        {
            dragToNodeDirection = draggingNodeCenter.y < draggedToNodeCenter.y ? Direction2D4.Up : Direction2D4.Down
        }
        else
        {
            dragToNodeDirection = Direction2D4.Right
        }
    
        if(userConfig.get("DEBUG"))
        {
            moveNodeIndicatorCircle.setVisible(true)
            const worldRect = draggedToNode.getWorldRect()
            moveNodeIndicatorCircle.moveTo(getRectPoint(worldRect, Direction2D4.toDirection2D9(dragToNodeDirection)))
        }
    }
}

function findClosestNodeFromTheirPoint(fromNode: Node, toGoalPoint: Direction2D9 = Direction2D9.Center, fromOriginPoint: Direction2D9 = Direction2D9.Center, filter: (node: Node) => boolean = noopTrue): [ Node, number ]
{
