function handleWorldKeyDown(e: KeyboardEvent)
{
	// log("viewport")

    lastKeyPressed = e.key.toLowerCase()

    let cancelOriginalAction = false

    const tab = get(currentTab)

    //#region tab commands
    const isLeftSidebarOpen = get(leftSidebarOpen)

    if(!isLeftSidebarOpen)
    {
        const [node] = getEventTargetNode(e)

        if(tab != null)
        {
            const firstNode = tab != null ? (tab.selectedNodes.size > 0 ? [...tab.selectedNodes][0] : null) : null
            const isCurrentlyTyping = isTyping()

            if(isCurrentlyTyping)
            {
                //#region typing
                if(firstNode != null)
                {
                    playPopSound()
            
                    switch(lastKeyPressed)
                    {
                        default:
                        {
                            cancelOriginalAction = false
                            break
                        }
            
                        case "escape":
                        case "enter":
                        {
                            const isEnter = lastKeyPressed == "enter"
        
                            if(isEnter && modifierStates[1])
                            {
                                break
                            }
        
                            firstNode.stopEditing(isEnter)
                            firstNode.focus()
                        }
                        break
        
                        case "shift":
                        {
        
                        }
                        break
                    }
                }
                //#endregion typing
            }
            else
            {
                //#region while not typing

                if(modifierStates[0])
                {
                    //ctrl held down
                    switch(lastKeyPressed)
                    {
                        case "a":
                        {
                            tab.selectNodes(tab.nodes, true)
                        }
                        break

                        case "i":
                        {
                            tab.invertSelectedNodes()
                        }
                        break
                    }
                }

                const anyModifierHeld = modifierStates.some(state => state)
                const isCharTyping = isTypingChar(lastKeyPressed)
        
                //#region specific node actions
                if(firstNode != null && !cancelOriginalAction)
                {
                    if(firstNode.canEditAgain())
                    {
                        switch(lastKeyPressed)
                        {
                            default:
                            {
                                cancelOriginalAction = false
                                break
                            }
        
                            case "f2":
                            {
                                firstNode.startEditing()
                            }
                            break
        
                            case "delete":
                            case "backspace":
                            {
                                tab.deleteSelectedNodes()
                            }
                            break
        
                            case "escape":
                            {
                                tab.deselectNodes()
                            }
                            break
        
                            case "enter":
                            {
                                tab.createChildForNodes(tab.selectedNodesArray, modifierStates[0], true)
                            }
                            break
                        }
        
                        if(!cancelOriginalAction)
                        {
                            if(isCharTyping)
                            {
                                if(!anyModifierHeld || AreModifiersOnly(1))
                                {
                                    // firstNode.text += lastKeyPressed
                                    firstNode.startEditing(" ")
                                }
                            }
                        }
                    }
                }
                //#endregion specific node actions
        
                if(!cancelOriginalAction)
                {
                    //#region multi node actions
                    let isKeyNavigation = false
        
                    switch(lastKeyPressed)
                    {
                        case "arrowup":
                        case "arrowdown":
                        case "arrowleft":
                        case "arrowright":
                        {
                            isKeyNavigation = true
                        }
                        break
                    }
        
                    if(isKeyNavigation)
                    {
                        tab.selectLastSelectedAliveNodeIfNoneSelected()
                    }
        
                    if(tab.selectedNodes.size > 0)
                    {
                        //#region navigation
                        switch(lastKeyPressed)
                        {
                            case "arrowup":
                            case "arrowdown":
                            {
                                cancelOriginalAction = true
                                
                                const navigatingNodes = getNavigatingNodes()
            
                                const up = lastKeyPressed == "arrowup"
                                const amount = up ? 1 : -1
            
                                if(modifierStates[2])
                                {
                                    tab.forEachSelectedNode(node => node.move(amount), lastNode => waitTick(1, () => lastNode.focus()))
                                }
                                else
                                {
                                    const toSelect: Set<Node> = new Set()
            
                                    for(const node of navigatingNodes)
                                    {
                                        if(node.isRoot)
                                        {
                                            continue
                                        }

                                        const siblingsCount = node.parent.getAliveChildrenCount()
                                        const childIndex = node.childIndex

                                        if(siblingsCount == 0 || (up ?  childIndex == 0 : childIndex == siblingsCount - 1))
                                        {
                                            if(raycastWorldForNodes(getRectCenter(node.getRect()), { x: 0, y: -amount }, (nextNode, pos, step) =>
                                            {
                                                if(nextNode == node)
                                                {
                                                    return false
                                                }
                
                                                toSelect.add(nextNode)
                                                return true
                                            }))
                                            {
                                                continue
                                            }
                                        }

                                        if(node.parent.children.length > 1)
                                        {
                                            const siblingNode = node.getSiblingNode(-amount, true)
                                            toSelect.add(siblingNode)
                                            continue
                                        }
            
                                        toSelect.add(node)
                                    }
            
                                    selectNavigatingNodes(toSelect)
                                }
                            }
                            break
            
                            case "arrowleft":
                            case "arrowright":
                            {
                                cancelOriginalAction = true
            
                                const navigatingNodes = getNavigatingNodes()
            
                                const left = lastKeyPressed == "arrowleft"
            
                                const toSelect: Set<Node> = new Set()
            
                                for(const node of navigatingNodes)
                                {
                                    let picked = false
                                    
                                    if(left)
                                    {
                                        if(!node.isRoot)
                                        {
                                            toSelect.add(node.parent)
                                            picked = true
                                        }
                                    }
                                    else
                                    {
                                        if(node.children.length > 0 && node.childrenVisible)
                                        {
                                            toSelect.add(node.getChildVerticallyClosestToParent())
                                            picked = true
                                        }
                                    }
            
                                    if(!picked)
                                    {
                                        toSelect.add(node)
                                    }
                                }
            
                                selectNavigatingNodes(toSelect)
                            }
                            break
                        }
                        //#endregion navigation
                    }
                    //#endregion multi node actions
                    //#endregion while not typing
                }
            }
        }
    }
    //#endregion tab commands

    if(cancelOriginalAction)
    {
        e.preventDefault()
        e.stopPropagation()
    }
}

//region handleWindowKeyDown
function handleWindowKeyDown(e: KeyboardEvent)
{
	// log("window")

    lastKeyPressed = e.key.toLowerCase()
    // log(`keydown: ${lastKeyPressed} | ${e.code} | ${e.keyCode} | isTyping: ${isTyping()}`)
    
    switch(lastKeyPressed)
    {
        case "control":
            modifierStates[0] = true
            doSelectionBoxDrag()
            break

        case "shift":
            modifierStates[1] = true
            doSelectionBoxDrag()
            break
        
        case "alt":
            modifierStates[2] = true
            break
    }

    switch(lastKeyPressed)
    {
        case "tab":
        {
            tabIndexUsingKeyboard = true
        }
        break
    }

    if(popupWindowType != null)
    {
        if(!modifierStates[0])
        {
            e.stopPropagation()
            e.preventDefault()
            return
        }
    }

    let cancelOriginalAction = false
    
    //#region app commands
    if(!cancelOriginalAction)
    {
        const tab = get(currentTab)
        
        if(modifierStates[0])
        {
            //#region ctrl
            cancelOriginalAction = true
    
            switch(lastKeyPressed)
            {
                default:
                {
                    cancelOriginalAction = false
                }
                break
    
                case "-":
                {
                    tab.camera.scaleZoom(1 / userConfig.get("SCROLL_ZOOM_SPEED"), pointerWorldLast)
                }
                break
    
                case "+":
                case "=":
                {
                    tab.camera.scaleZoom(userConfig.get("SCROLL_ZOOM_SPEED"), pointerWorldLast)
                }
                break
            }

            if(!cancelOriginalAction && !isTyping())
            {
                cancelOriginalAction = true

                switch(lastKeyPressed)
                {
                    default:
                    {
                        cancelOriginalAction = false
                    }
                    break

                    case "s":
                    {
                        if(modifierStates[1])
                        {
                            saveToGoogleDrive()
                        }
                        else
                        {
                            save("Ctrl + S")
                        }
                        modifierStates[0] = false
                    }
                    break

                    case "f":
                    {

                    }
                    break
        
                    case "o":
                    {
                        if(modifierStates[1])
                        {
                            openProjectPickerFromGoogleDrive(true)
                        }
                        else
                        {
                            openFilePickerProject()
                        }
                    }
                    break

                    case "p": break
        
                    case "x":
                    case "c":
                    {
                        tab.copySelectedNodesToClipboard(lastKeyPressed == "x", !modifierStates[1])
                    }
                    break
        
                    case "v":
                    {
                        tab.pasteFromClipboard()
                    }
                    break
                
                    case "z":
                    {
                        if(modifierStates[1])
                        {
                            redo()
                        }
                        else
                        {
                            undo()
                        }
                    }
                    break
        
                    case "y":
                    {
                        redo()
                    }
                    break
                }
            }
            //#endregion ctrl
        }
    }
    //#endregion app commands

    if(cancelOriginalAction)
    {
        e.preventDefault()
        e.stopPropagation()
    }
}

