async function save(source: string): Promise<boolean>
{
    const data = projectToJsonString()

    if(data == null)
    {
        return false
    }

    messages.addMessage(`Saving project...`)

    saveToLocalStorage(source)

    try
    {
        if("showSaveFilePicker" in window)
        {
            const handle = await (window as any).showSaveFilePicker
            ({
                suggestedName: `${formatDate(new Date())}.json`,
                types:
                [
                    {
                        description: `${APP_NAME} JSON File`,
                        accept:
                        {
                            "application/json": [".json"]
                        }
                    }
                ]
            })

            const writable = await handle.createWritable()
    
            await writable.write(data)
            await writable.close()

            messages.addSuccessMessage(`Project saved to file!`)
        }
        else
        {
            const blob = new Blob([data], { type: "application/json" })

            const a = document.createElement("a")

            const url = URL.createObjectURL(blob)

            a.href = url
            a.download = `${name}.json`

            a.click()

            URL.revokeObjectURL(url)

            messages.addSuccessMessage(`Project downloaded!`)
        }
    }
    catch(e)
    {
        console.error(`Failed to save project file:`, e)

        let message = errorToString(e)
        message = message.replace("Failed to execute 'showSaveFilePicker' on 'Window': ", "").trim()

        messages.addWarningMessage(`Failed to save project file!\n${message}`)
        return false
    }

    return true
}

async function openFilePickerJsonAsString(): Promise<string>
{
    try
    {
        if("showOpenFilePicker" in window)
        {
            const filePicker = await (window as any).showOpenFilePicker
            ({
                types:
                [
                    {
                        description: `${APP_NAME} JSON File`,
                        accept:
                        {
                            "application/json": [".json"]
                        }
                    }
                ],
                multiple: false,
            })

            const handle = filePicker[0]

            const file = await handle.getFile()

            const text = await file.text()

            return text
        }
        else
        {
            const file = document.createElement("input")
            file.type = "file"
            file.accept = "application/json"
            
            file.onchange = () =>
            {
                const selectedFile = file.files?.[0]

                if(selectedFile != null)
                {
                    const reader = new FileReader()

                    reader.onload = () =>
                    {
                        const text = reader.result as string

                        return text
                    }

                    reader.readAsText(selectedFile)
                }
            }
            
            file.click()
        }
    }
    catch(e)
    {
        console.error(`Failed to load project file:`, e)
    }

    return null!
}

