        messages.addErrorMessage(text)
    }

    return false
}

async function setProjectFromJson(json: any): Promise<boolean>
{
    if(popupWindowType == "welcome")
    {
        popupWindowType = null!
    }

    leftSidebarSelectedTabName.set("Tabs")

    const type = getJsonType(json)

    // console.log(`Setting project from JSON of type: ${type}`)

    if(type == "unknown")
    {
        return false
    }

    const timer = new Timer()

    const timerPrint = (text: any) =>
    {
        console.log(`[${softToFixed(timer.elapsedS)}s] ${text}`)
    }

    closeProject()
    incrementProjectNumber()
    projectConfig.setFromJson(json.config)
    const madeTabs: Tab[] = []
    let currentTabIndex = 0

    switch(type)
    {
        case "project":
        {
            const projectJson: ProjectJson = json as ProjectJson
            if("indexOfSelectedTab" in projectJson)
            {
                currentTabIndex = projectJson.indexOfSelectedTab
            }

            
            if("tabs" in projectJson)
            {
                timerPrint(`Tabs Start`)

                for(const tabJson of projectJson.tabs as TabJson[])
                {
                    try
                    {
                        const tab = Tab.fromJson(tabJson, false)
                        
                        madeTabs.push(tab)

                        timerPrint(`Tab ${tab.name}`)
                    }
                    catch(e)
                    {
                        console.error("Failed to create tab from JSON:", e)
                        messages.addMessage(`Failed to create tab from JSON: ${errorToString(e)}`)
                        
                        timerPrint(tabJson)
                    }
                }

                timerPrint(`Tabs End`)
            }
        }
        break

        case "node":
        {
            const tab = Tab.fromNodeJson(json as NodeJson)

            madeTabs.push(tab)
        }
        break
    }

    if(madeTabs.length == 0)
    {
        const tab = new Tab(null!)
        const data = new NodeData(undefined, "New Tab")
        const rootNode = new Node(tab, data, null!)

        tab.setRootNode(rootNode)

        madeTabs.push(tab)
    }

    const tabToSelect = softArrayGet(madeTabs, currentTabIndex) ?? getLast(madeTabs)
    
    timerPrint(`Setting Tabs Start`)
    tabs.set(madeTabs)
    timerPrint(`Setting Tabs End`)
    timerPrint(`Tick Start`)
    await tick()
    timerPrint(`Tick End`)
    timerPrint(`Select Tab Start`)
    await tabToSelect.select()
    timerPrint(`Select Tab End`)

    nodeSearchResultsCache

    for(const tab of madeTabs)
    {
        nodeSearchResultsCache[tab.name] = tab.nodes
    }

    timerPrint(`Finished setting project from JSON!`)
    timerPrint(`${madeTabs.length} tab${sIfNot1(madeTabs.length)} loaded!`)
    // console.log(tabToSelect)
    // console.log(tabToSelect.rootNode.toText(false))

    // setDebugText("styles", [...stylesMap.values()].map(style => style.jsonStyle))

    return true
}

