async function loadProjectFromBrowserStorage(): Promise<boolean>
{
    messages.addMessage("Loading project from Browser Storage...")

    const data = localStorage.getItem(LAST_PROJECT_DATA)

    if(data == null)
    {
        return false
    }

    try
    {
        const nodeJson = JSON.parse(data)
        
        console.log(`Loaded file!`)
        console.log(nodeJson)

        messages.addSuccessMessage(`Local storage project loaded!`)

        return await setProjectFromJson(nodeJson)
    }
    catch(e)
    {
        const message = errorToString(e)
        console.error("Failed to load project from local storage:", e)
        messages.addMessage(`Failed to load project from local storage: ${message}`)
        
        return false
    }
}

async function saveToGoogleDrive(name: string = formatDate(new Date()))
{
    const stringifiedProjectJson = projectToJsonString()

    if(stringifiedProjectJson == null)
    {
        return
    }

    const response = await saveJsonToGoogleDrive(name, stringifiedProjectJson, projectConfig.get("GOOGLE_DRIVE_FILE_ID"))

    if(response != null)
    {
        const json = await response.json()

        console.log(`[saveToGoogleDrive] Received:`)
        console.log(json)

        if(isString(json.id))
        {
            projectConfig.set("GOOGLE_DRIVE_FILE_ID", json.id)
        }

        setGoogleDriveQueryPromise(setAppFilesToGoogleDriveFolder())
    }
}

async function openProjectPickerFromGoogleDrive(doSidebar: boolean, autoOpenIfOnlyOne: boolean = userConfig.get("GOOGLE_DRIVE_AUTOOPEN_IF_ONE_PROJECT"))
{
    if(isGoogleDriveQueryInProgress())
    {
        messages.addWarningMessage("Already loading files from Google Drive...")
    }
    else
    {
        messages.addMessage("Loading files from Google Drive...")
        const folderId = await createGoogleDriveAppFolderSoft()

        await setGoogleDriveQueryPromise(setAppFilesToGoogleDriveFolder(folderId))

        const files = get(appFiles)

        const close = () =>
        {
            if(doSidebar)
            {
                setLeftSidebarOpen(true)
                leftSidebarSelectedTabName.set("GDrive")
            }
            else
            {
                popupWindowType = null
            }
        }

        if(files.length > 0)
        {
            userAccessedGoogleDrive.set(true)

            let fileToOpen: AppFile = null!

            if(autoOpenIfOnlyOne)
            {
                let nonFolderCount = 0
                let lastFile: AppFile = null!
    
                for(const file of files)
                {
                    if(!isAppFileFolder(file))
                    {
                        ++nonFolderCount
                        lastFile = file
                    }
                }
    
                const fileCount = files.length - nonFolderCount
    
                if(fileCount == 1)
                {
                    fileToOpen = lastFile
                }
            }

            if(fileToOpen != null)
            {
                messages.addSuccessMessage(`Auto-opening only project ${fileToOpen.name} from Google Drive...`)
                close()
                await onItemPickedFromGoogleDrive(fileToOpen, doSidebar)
            }
            else if(doSidebar)
            {
                close()
            }
        }
    }
}

async function onItemPickedFromGoogleDrive(item: AppFile, doSidebar: boolean)
{
    if(isGoogleDriveQueryInProgress())
    {
        messages.addMessage("Already loading files from Google Drive...")
        return
    }

    const isFolder = isAppFileFolder(item)

    console.log(`picked ${item.name}! Folder: ${isFolder}`)

    if(isFolder)
    {
        return await onFolderPickedFromGoogleDrive(item.id)
    }
    else
    {
        messages.addMessage(`Loading project ${item.name}...`)

        if(doSidebar)
        {
            setLeftSidebarOpen(false)
            leftSidebarSelectedTabName.set("Tabs")
        }

        await loadProjectFromGoogleDrive(item.id)
    }
}
async function onFolderPickedFromGoogleDrive(id: string)
{
    await setGoogleDriveQueryPromise(setAppFilesToGoogleDriveFolder(id))
}
