function onSidebarOpenOrClose(leftOrRight: boolean, openedOrClosed: boolean)
{
    // log(`[${leftOrRight ? "Left" : "Right"}] External: ${Date.now()}`)

    if(leftOrRight)
    {
        leftSidebarOpen.set(openedOrClosed)
    }
    else
    {
        rightSidebarOpen.set(openedOrClosed)
    }

    // log(`${leftOrRight ? "Left" : "Right"} sidebar was ${openedOrClosed ? "opened" : "closed"}!`)

    if(openedOrClosed)
    {
        const elA = leftOrRight ? leftSidebarEl : rightSidebarEl
        const elB = leftOrRight ? rightSidebarEl : leftSidebarEl

        const bbA = elA.getBoundingClientRect()
        const bbB = elB.getBoundingClientRect()

        const widthA = bbA.width
        const widthB = bbB.width
    
        const windowWidth = window.innerWidth

        const widthRatioA = widthA / windowWidth
        const widthRatioB = widthB / windowWidth

        const totalWidthRatio = widthRatioA + widthRatioB

        // log(`total width ratio: ${totalWidthRatio} | ${widthRatioA} + ${widthRatioB}`)

        if(0.95 <= totalWidthRatio)
        {
            setSidebarVisible(!leftOrRight, false)
        }
    }
    else
    {
        setSidebarVisible(!leftOrRight, true)
    }
}

