            {:else}
                No Tab
            {/if}
        </div>

        {#if $currentTab != null}
            {#if $isTouch}
            <div class="bottom_right_buttons"
                style:bottom={$viewportGapY + 8}px
                >
                <ButtonComp
                    index={0}
                    // disabled={$currentTab.selectedNodes.size == 0 || $currentTab.getLastSelectedAliveNode().isRoot}
                    onClick={() => get(currentTab).deleteSelectedNodes()}
                    title="-"
                    />
                <ButtonComp
                    index={1}
                    // disabled={$currentTab.selectedNodes.size == 0 || $currentTab.getLastSelectedAliveNode().isRoot}
                    onClick={() => get(currentTab).createChildForSelectedNodes(false, true)}
                    title="+"/>
                <ButtonComp
                    index={2}
                    // disabled={$currentTab.selectedNodes.size == 0}
                    onClick={() => get(currentTab).createChildForSelectedNodes(true, true)}
                    title={`${ARROW_RIGHT}+`}/>
            </div>
            <div class="bottom_left_buttons"
                style:bottom={$viewportGapY + 8}px
                >
                <ButtonComp
                    index={1}
                    // disabled={$remainingUndoCount == 0}
                    onClick={() => undo()}
                    title={ARROW_LEFT}/>
                <ButtonComp
                    index={0}
                    // disabled={$remainingRedoCount == 0}
                    onClick={() => redo()}
                    title={ARROW_RIGHT}/>
            </div>

            <div class="top_right_buttons">
                <ButtonComp
                    index={0}
                    // disabled={$currentTab.selectedNodes.size == 0}
                    onClick={() => $currentTab.copySelectedNodesToClipboard(false, true)}
                    title="🌱"/>
                <ButtonComp
                    index={1}
                    // disabled={$currentTab.selectedNodes.size == 0 || $currentTab.getLastSelectedAliveNode().isRoot}
                    onClick={() => $currentTab.copySelectedNodesToClipboard(true, true)} title="✂️"/>
                <ButtonComp
                    index={2}
                    // disabled={$currentTab.selectedNodes.size == 0}
                    onClick={() => $currentTab.pasteFromClipboard()}
                    title="🌳"/>
            </div>
            {/if}
        
            {#snippet nodesPropertiesTab()}
            <NodesPropertiesPanelComp
                />
            {/snippet}

            {#snippet nodesTagsTab()}
            <NodesTagsPanelComp
                nodes={$currentTab.selectedNodesDataArray}
                />
            {/snippet}
            
            {#snippet nodesStyleTab()}
            <NodesStylePanelComp
                
                />
            {/snippet}

            <!-- #region Right Sidebar -->
            <SideBarComp
                bind:el={rightSidebarEl}
                openOrCollapsed={$rightSidebarOpen}
                visible={$rightSidebarVisible}
                onOpenOrCollapsedChange={(open) => onSidebarOpenOrClose(false, open)}
                leftOrRight={false}
                openOnHover={false}
                >
                <div
                    style:text-align="center"
                    >
                    {#if $currentTab != null}
                    ~Node Properties~
                    {/if}
                </div>
                <TabsPanelComp
                    tabs=
                    {same<RightSidebarTabs>
                    ({
                        Properties: nodesPropertiesTab,
                        Tags: nodesTagsTab,
                        Style: nodesStyleTab,
                    })}
                    selectedTabName={$rightSidebarSelectedTabName}
                    onInternalTabChange={(name) => rightSidebarSelectedTabName.set(name)}
                />
            </SideBarComp>
            <!-- #endregion Right Sidebar -->
        {/if}
    
        <!-- #region Left Sidebar -->
        {#snippet tabsTab()}
        <div>
            <TabsComp
            />
        </div>
        {/snippet}

        {#snippet fileTab()}
        <ButtonsPanelComp
            items=
            {[
                { title: "Save to Google Drive", action: () => saveToGoogleDrive() },
                { title: "Save", action: () => save("Save Button") },
                { title: "Load from Google Drive", action: () => openProjectPickerFromGoogleDrive(true) },
                { title: "Load from Browser", action: () => loadProjectFromBrowserStorage() },
                { title: "Load from Device", action: () => openFilePickerProject() },
                { title: "Open Welcome Screen", action: () => popupWindowType = "welcome" },
            ]}
        />
        {/snippet}

        {#snippet cameraTab()}
        <ButtonsPanelComp
            items=
            {[
                { title: "Reset Camera", action: () => $currentTab.camera.centerToNode($currentTab.rootNode) },
            ]}
        />
        {/snippet}

        {#snippet actionsTab()}
        <SectionsPanelComp
            sections=
            {[
                {
                    title: "File",
                    section: fileTab,
                },
                {
                    title: "Camera",
                    section: cameraTab,
                },
            ]}
        />
        {/snippet}

        {#snippet searchTab()}
        <NodeSearchComp>
            
        </NodeSearchComp>
        {/snippet}

        {#snippet loadGoogleDriveTab()}
        <GoogleDrivePanelComp
            onItemPicked={(item) => onItemPickedFromGoogleDrive(item, true)}
            onParentPicked={onFolderPickedFromGoogleDrive}
            />
        {/snippet}
        
        <SideBarComp
            bind:el={leftSidebarEl}
            openOrCollapsed={$leftSidebarOpen}
            visible={$leftSidebarVisible}
            onOpenOrCollapsedChange={(open) => onSidebarOpenOrClose(true, open)}
            leftOrRight={true}
            openOnHover={true}
            >
            <TabsPanelComp
                tabs=
                {same<LeftSidebarTabs>
                ({
                    Tabs: tabsTab,
                    Actions: actionsTab,
                    Search: searchTab,
                    ...(get(userAccessedGoogleDrive) ? { GDrive: loadGoogleDriveTab } : {}),
                })}
                selectedTabName={$leftSidebarSelectedTabName}
                onInternalTabChange={(name) => leftSidebarSelectedTabName.set(name)}
            />
        </SideBarComp>
        <!-- #endregion Left Sidebar -->
    </div>
    <!-- Messages -->
    <div class="notifications">
        {#each $messages as message (message.id)}
            <MessageComp {message}/>
        {/each}
    </div>

    {#if popupWindowType != null}
        {#if popupWindowType == "welcome"}
            <WindowComp
                closable={$currentTab != null}
                onClose={() =>
                {
                    if(get(currentTab) == null)
                    {
                        loadInitialProject()
                    }

                    popupWindowType = null
                }}
                title="~Welcome to {APP_NAME}!~"
            >
                <ButtonsPanelComp
                    items={welcomeScreenOpenOptions}
                >
                {#snippet header()}
                    <div class="centered_text">~Open Project~</div>
                {/snippet}
                </ButtonsPanelComp>
                {#if $appFiles.length > 0}
                    <GoogleDrivePanelComp
                        onItemPicked={(item) => onItemPickedFromGoogleDrive(item, false)}
                        onParentPicked={onFolderPickedFromGoogleDrive}
                        />
                {/if}
                <PanelComp>
                    <!-- {#snippet header()}
                    <div class="centered_text">~News~</div>
                    {/snippet} -->
                    <div
                        style:width=100%
                        style:text-align=center
                        >
                        <!-- svelte-ignore a11y_click_events_have_key_events -->
                        <!-- svelte-ignore a11y_no_noninteractive_element_interactions -->
                        <img
                            src={ponyUrl}
                            onclick={newPonyUrl}
                            alt="Cutesie Pony~"
                            style:max-width=100%
                            style:margin-top=6px
                        >
                    </div>
                </PanelComp>

            </WindowComp>
        {/if}
    {/if}
    {#if $contextMenuState.type != null}
        {#if $contextMenuState.type == "tab"}
            <TabContextMenuComp
                origin={pointerLast}
                data={$contextMenuState}
                />
        {:else if $contextMenuState.type == "node"}
            <NodeContextMenuComp
                data={$contextMenuState}
                />
        {/if}
    {/if}
</div>

