<script lang="ts">
    import type { Snippet } from "svelte";
    import { Style } from "../data/styles";
    import { ifOrElse0 } from "../util/util.svelte";
    import { playPopSound } from "../data/audio";

    let
    {
        onClick,
        title,
        contentSnippet,
        extraClass,
        index = 0,
        style = Style.DEFAULT,
        disabled = false,
        hovered = false,
        fontSize,
        width = "auto",
        selected = null,
        draggable = false,
        onDragStart,
        onDragEnd,
    }:
    {
        onClick?: (e: MouseEvent) => void,
        title?: string,
        contentSnippet?: Snippet,
        extraClass?: string,
        index?: number,
        style?: Style,
        disabled?: boolean,
        hovered?: boolean,
        fontSize?: string,
        width?: string,
        selected?: boolean | null,
        draggable?: boolean,
        onDragStart?: (e: MouseEvent) => void,
        onDragEnd?: (e: MouseEvent) => void,
    } = $props()

    function getOffset(ifValue: number = 0.25)
    {
        if(disabled)
        {
            return -0.25
        }

        if(hovered)
        {
            return ifValue
        }

        if(selected != null)
        {
            return ifOrElse0(selected, ifValue)
        }

        return 0
    }
</script>

<button
    style:--bg-color={style.getDynamicColor(index, 0, selected ? 1 : getOffset(), 0)}
    style:background-color={"var(--bg-color)"}
    style:border-bottom-color={(hovered || selected) ? style.getDynamicColor(index, 0, getOffset(1), getOffset(0.35)) : "var(--bg-color)"}
    style:font-size={fontSize ?? style.get("fontSize")}
    style:font-family={style.get("fontFamily")}
    style:width={width}
    class="button {extraClass}"
    title={title ?? ""}
    onclick={e => {onClick?.(e); playPopSound()}}
    disabled={disabled}
    onmouseenter={() => hovered = true}
    onmouseleave={() => hovered = false}
    >
    {#if title != null}
        {title}
    {/if}
    {@render contentSnippet?.()}
</button>

<style>
.button
{
    padding: 6px 12px;
    border-radius: 12px;

    background-color: #ff007764;
    color: white;

    border: none;
    cursor: pointer;

    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.2);

    pointer-events: auto;

    border-bottom-width: 2px;
    border-bottom-style: solid;
}
</style>