<script lang="ts" generics="K extends {[key: string]: number | string | boolean}, V">
    import type { Snippet } from "svelte";
    import PanelComp from "./PanelComp.svelte";
    import ButtonComp from ".././ButtonComp.svelte";
    import { noopTrue } from "../../util/util.svelte";
    import { HAMBURGER, RED_X } from "../../data/finals";
    import { playPopSound } from "../../data/audio";

    let
    {
        items,
        itemSnippet,
        itemWidth = "100%",
        alignItems = "center",
        onItemPicked = noopTrue,
        header,
        footer,
        createNewInputs = {} as K,
        createNew,
        onDelete = undefined,
        onHamburger = undefined,
        gap = "4px",
        background,
        flexDirection = "column",
    }:
    {
        items: V[]
        itemSnippet: Snippet<[V, number]>
        itemWidth?: string
        alignItems?: string
        onItemPicked?: (item: V, index: number, e: MouseEvent) => void
        header?: Snippet
        footer?: Snippet
        onClose?: () => void
        createNewInputs?: K
        createNew?: () => V | void
        gap?: string
        onDelete?: (item: V, index: number) => void
        onHamburger?: (item: V, index: number) => void
        background?: string
        flexDirection?: "column" | "row"
    } = $props()
</script>

<PanelComp
    header={header}
    footer={footer}
    background={background}
    >
    <div class="items_panel"
        style:display=flex
        style:flex-direction={flexDirection}
        style:gap={gap}
        style:align-items={alignItems}
        >
        {#each items as item, i}
        <button
            class="item"
            onclick={(e) => onItemPicked(item, i, e)}
            style:width={itemWidth}
            style:display="flex"
            >
                {#if onDelete != null}
                <ButtonComp
                    title={RED_X}
                    index={i}
                    onClick={e =>
                    {
                        onDelete(item, i)
                    }}
                    />
                {/if}
                {#if onHamburger != null}
                <ButtonComp
                    title={HAMBURGER}
                    index={i}
                    onClick={e =>
                    {
                        onHamburger(item, i)
                    }}
                    />
                {/if}
                <div style:width={itemWidth}>
                    {@render itemSnippet(item, i)}
                </div>
        </button>
        {/each}
        {#if createNew != null}
        {#each Object.keys(createNewInputs) as key}
            {key}: {createNewInputs[key]}
        {/each}
        <ButtonComp
            index={items.length}
            width="100%"
            title="+"
            fontSize="0.8em"
            onClick={() =>
            {
                const newItem = createNew()

                if(newItem != null)
                {
                    playPopSound()
                }
            }}
        />
        {/if}
    </div>
</PanelComp>

<style>
.items_panel
{
    overflow: auto;
    
}

.item
{
    all: unset;
    pointer-events: auto;
}
</style>