<script lang="ts">
    import { Style } from "../../data/styles";
    import ButtonsPanelComp from "../panels/ButtonsPanelComp.svelte";
    import { contextMenuState, EMPTY_CONTEXT_MENU, noModifiersHeld, type TabContextMenuType } from "../../comps_data/app.svelte";
    import { tabs } from "../../comps_data/tabs.svelte";

let
{
    style = Style.DEFAULT,
    data: data,
}:
{
    style?: Style
    data: TabContextMenuType
} = $props()

const tab = data.targets[0]
</script>

<div class="title">{tab.name}</div>
<ButtonsPanelComp
    style={style}
    afterItemClicked={(data) =>
    {
        if(data.title.includes("Move"))
        {
            return
        }

        if(noModifiersHeld() || data.title.includes("Delete"))
        {
            contextMenuState.set(EMPTY_CONTEXT_MENU)
        }
    }}
    items=
    {[
        { title: "Select", action: () => { tab.select() } },
        ...($tabs.length <= 1 ? [] :
        [
            { title: "Move Up", action: () => { tab.move(-1) }},
            { title: "Move Down", action: () => { tab.move(1) }},
        ]),
        { title: "Delete", action: () => { tab.delete() }},
    ]}
/>