<script lang="ts">
import type { Snippet } from "svelte";
import { Style } from "../data/styles";
import { ARROW_LEFT, ARROW_RIGHT, HACK_WAIT_MS } from "../data/finals";
import { clearSidebarDebounce, isSidebarOnDebounce, isTouch, startSidebarDebounce } from "../comps_data/app.svelte";
import { playPopSound } from "../data/audio";
import { noopVoid } from "../util/util.svelte";

let
{
    el = $bindable(),
    children,
    leftOrRight,
    openOrCollapsed = false,
    openOnHover = false,
    closeOnLeave = false,
    onHover = noopVoid,
    onLeave = noopVoid,
    visible = true,
    onOpenOrCollapsedChange,
    style = Style.DEFAULT,
}:
{
    el?: HTMLElement,
    children: Snippet
    leftOrRight: boolean
    openOrCollapsed?: boolean
    openOnHover?: boolean
    closeOnLeave?: boolean
    visible?: boolean
    onHover?: (e: MouseEvent) => void
    onLeave?: (e: MouseEvent) => void
    onOpenOrCollapsedChange?: (newValue: boolean) => void
    style?: Style
} = $props()

let contentInteractable = $state(false)

function areInteractionsBlocked()
{
    if(!visible)
    {
        // log("invisible")
        return true
    }

    if(isSidebarOnDebounce(leftOrRight))
    {
        // log("debounce")
        return true
    }

    return false
}

function toggleOpen()
{
    if(areInteractionsBlocked())
    {
        return
    }

    startSidebarDebounce()

    // log(`[${leftOrRight ? "Left" : "Right"}] Internal: ${Date.now()}`)
    
    playPopSound()
    openOrCollapsed = !openOrCollapsed

    if(el != null)
    {
        const width = el.getBoundingClientRect().width

        const widthRatio = width / window.innerWidth

        if(widthRatio < 0.95)
        {
            clearSidebarDebounce(!leftOrRight)
        }
    }

    // log("Toggled sidebar open/collapsed. New state: " + openOrCollapsed)
    // log(`Portrait: ${$isPortrait}, Touch: ${$isTouch}`)

    if (onOpenOrCollapsedChange) onOpenOrCollapsedChange(openOrCollapsed)

    contentInteractable = false
    setTimeout(() => contentInteractable = true, HACK_WAIT_MS)
}

function onOpenColapseButtonHover()
{
    if(areInteractionsBlocked())
    {
        return
    }

    if (openOnHover && !openOrCollapsed)
    {
        toggleOpen()
    }    
}
</script>

<div
    bind:this={el}
    class="sidebar {leftOrRight ? 'left_sidebar' : 'right_sidebar'}"
    role="menubar"
    tabindex=-1
    style:display={visible ? "flex" : "none"}
    style:flex-direction={leftOrRight ? "row" : "row-reverse"}
    style:background-color={Style.DEFAULT.get("background")}
    onmouseleave={(e) =>
    {
        if (closeOnLeave && openOrCollapsed)
        {
            toggleOpen()
        }

        onLeave?.(e)
    }}
    onmouseenter={(e) =>
    {
        onHover?.(e)
    }}
    style:opacity={openOrCollapsed ? style.get("uiOpacity") : 0.2}
    >

    <div
        style:display={openOrCollapsed ? "block" : "none"}
        style:max-width={$isTouch ? "95vw" : "99vw"}
        style:direction={leftOrRight ? "rtl" : "ltr"}
        class={contentInteractable ? "" : "no_pointer_events"}
        >
        {@render children()}
    </div>
    <button
        class="open_collapse_button"
        type="button"
        onclick={toggleOpen}
        onmouseenter={onOpenColapseButtonHover}
        style:width={$isTouch ? "5vw" : "1vw"}
    >
        {leftOrRight ? (openOrCollapsed ? ARROW_LEFT : ARROW_RIGHT) : (openOrCollapsed ? ARROW_RIGHT : ARROW_LEFT)}
    </button>
</div>

<style>
.no_pointer_events,
.no_pointer_events :global(*)
{
    pointer-events: none;
}

.sidebar
{
    display: flex;
    flex-direction: row;
    position: fixed;
    
    width: auto;

    height: 100dvh;

    pointer-events: auto;
    outline: none;
}

.left_sidebar
{
    left: 0px;
}

.right_sidebar
{
    right: 0px;
}

.open_collapse_button
{
    -webkit-text-stroke: 0;
    font-size: 8px;
    width: 1vw;
    height: inherit;
    border-radius: 4px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    pointer-events: auto;
    background: inherit;
}
</style>