<script lang="ts">
    import type { Tag } from "../comps_data/tags.svelte";
    import { EMPTY_BOX } from "../data/finals";
    import { noopTrue } from "../util/util.svelte";
    import InputLabelComp from "./InputLabelComp.svelte";

    // export let tag: Tag

    let
    {
        tag,
        onNameChange = noopTrue,
        onValueChange = noopTrue,
        editable = false,
        onlyDisplayValueIfNotEmpty = false,
    } :
    {
        tag: Tag
        onNameChange?: (newName: string) => unknown | string
        onValueChange?: (newValue: string) => unknown | string
        editable?: boolean
        onlyDisplayValueIfNotEmpty?: boolean
    } = $props()
</script>

<div class="tag"
    bind:this={tag.el}
    style:background={tag.getBackgroundColor()}
    >
    <InputLabelComp
        startEditingOnDoubleClick={editable}
        value={tag.name}
        onBlur={((e, newName) =>
        {
            if(tag.name == newName)
            {
                return
            }

            return onNameChange(newName)
        })}
    />

    {#if !onlyDisplayValueIfNotEmpty || tag.hasValue}
    : 
    <InputLabelComp
        startEditingOnDoubleClick={editable}
        value={tag.value}
        labelValue={tag.value.length > 0 ? tag.value : EMPTY_BOX}
        onBlur={((e, newValue) =>
        {
            if(tag.value == newValue)
            {
                return
            }

            return onValueChange(newValue)
        })}
    />
    {/if}
</div>

<style>
    .tag
    {
        background: lightblue;
        width: max-content;
        height: max-content;
        border-radius: 8px;
        padding: 2px 6px;

        display: flex;
        flex-wrap: nowrap;
    }

    .value
    {
        
    }
</style>