<script lang="ts">
import { Style } from "../../data/styles";
import PanelComp from "./PanelComp.svelte";
import { forEveryTab } from "../../comps_data/tabs.svelte";
import { nodeSearchResultsCache, nodeSearchText, setNodeSearchText } from "../../comps_data/app.svelte";
import type { Node } from "../../comps_data/nodes.svelte";
import { clearObj } from "../../util/util.svelte";
import NodesPanel from "./NodesPanel.svelte";
import { centerToNode } from "../../comps_data/cameras.svelte";

let
{
    style = Style.DEFAULT,
    replace = false,
} :
{
    style?: Style,
    replace?: boolean,
} = $props()

// let nodes: Node[] = $state(getOrCreateObj(nodeSearchResultsCache, "", () => ([])))
let nodes: {[key: string]: Node[]} = $state(nodeSearchResultsCache)

function onSearchChange(e: Event)
{
    const el = e.target as HTMLTextAreaElement

    setNodeSearchText(el.value)

    const searchFor = el.value.toLowerCase()

    // const cacheNodes = getOrCreateObj(nodeSearchResultsCache, searchFor, () => ([]))
    const cacheNodes = nodeSearchResultsCache
    clearObj(cacheNodes)

    forEveryTab(tab =>
    {
        const matches: Node[] = []

        tab.forEachNode(node =>
        {
            if(node.identityTheftBy.size > 0 || node.mimicOf != null)
            {
                return
            }

            const data = node.data

            if(data.text.toLowerCase().includes(searchFor))
            {
                matches.push(node)
                return
            }

            for(const tag of data.tagsComps)
            {
                if(tag.name.toLowerCase().includes(searchFor))
                {
                    matches.push(node)
                    return
                }
            }
        })

        if(matches.length > 0)
        {
            cacheNodes[tab.name] = matches
        }
    })

    // log(`search results: ${nodeSearchResultsCache.length}`)

    nodes = cacheNodes
}
</script>

<!-- <div
    style:display=flex
    style:flex-align="row"
    >

    <ButtonsPanelComp
        items={[]}
        /> -->
    <PanelComp>
        <div class="row"
        >
            <textarea class="text"
                autocomplete="off"
                rows=1
                style:font-size={style.get("fontSize")}
                style:color={style.get("textColor")}
                placeholder="Search..."
                onchange={onSearchChange}
                oninput={onSearchChange}
                value={nodeSearchText}
            ></textarea>
            {#if replace}
                <textarea class="text"
                    rows=1
                    style:font-size={style.get("fontSize")}
                    style:color={style.get("textColor")}
                    placeholder="Replace..."
                ></textarea>
            {/if}
        </div>
        <!-- results -->
        {#each Object.entries(nodes) as [tabName, matches], i}
            <div class="title"
                style:margin-top="{i == 0 ? 0 : 25}px"
                style:background-color={matches[0].rootNode.getBackgroundColor()}
            >
                {tabName}
                <NodesPanel
                    // background={matches[0].rootNode.getBackgroundColor(0, 0, 0, -0.35)}
                    background={`linear-gradient(to bottom, ${matches[0].rootNode.getBackgroundColor(0, 0, 0, -0.1)}, ${matches[0].rootNode.getBackgroundColor(0, 0, 0, -0.35)})`}
                    nodes={matches}
                    onNodeClick={(node) =>
                    {
                        centerToNode(node)
                    }}
                    />
            </div>
        {/each}
    </PanelComp>
<!-- </div> -->

<style>
.row
{
    display: flex;
    flex-direction: column;
}

.text
{
    height: min-content;
}
</style>