<script lang="ts">
import type { Snippet } from "svelte";
import { Style } from "../../data/styles";
import { contextMenuState } from "../../comps_data/app.svelte";
import PanelComp from "../panels/PanelComp.svelte";

let
{
    el = $bindable(),
    title,
    header,
    children,
    footer,
    style = Style.DEFAULT,
}:
{
    el?: HTMLDivElement
    title?: string
    header?: Snippet
    children: Snippet
    footer?: Snippet
    style?: Style
} = $props()

function afterBind(e: HTMLDivElement)
{
    contextMenuState.update(context =>
    {
        const rect = e.getBoundingClientRect()

        if(rect.right > window.innerWidth)
        {
            rect.x -= rect.right - window.innerWidth
        }

        if(rect.bottom > window.innerHeight)
        {
            rect.y -= rect.bottom - window.innerHeight
        }

        context.rect = rect

        return context
    })
}
</script>

<div class="context_menu"
    bind:this={el}
    use:afterBind
    style:background-color={style.get("background")}

    style:opacity={style.get("uiOpacity")}

    style:left={$contextMenuState.rect.x + "px"}
    style:top={$contextMenuState.rect.y + "px"}
    >
    {#if title != null}
        <div class="title">
            {title}
        </div>
    {/if}
    <PanelComp
        header={header}
        footer={footer}
    >
        {@render children()}
    </PanelComp>
</div>

<style>
.context_menu
{
    position: absolute;
    z-index: 1000;

    border-radius: 8px;
    padding: 8px;

    pointer-events: all;
}
</style>