import type { NodeBase } from "../comps_data/nodes.svelte"
import type { ProjectConfigJson } from "../data/projectConfig"
import type { StyleJson } from "../data/styles"
import type { String2Record } from "./types"

export interface Pos
{
    x: number,
    y: number,
}

export namespace Pos
{
    export function zero(): Pos
    {
        return { x: 0, y: 0 }
    }

    export function clone(pos: Pos)
    {
        return { x: pos.x, y: pos.y }
    }

    export function from(x: number, y: number): Pos
    {
        return { x, y }
    }
}

export interface Size
{
    width: number,
    height: number,
}

export interface SimpleCamera extends Pos
{
    zoom: number,
}

export interface IJsonable
{
    toJson(): any
}

export interface NodeJson extends NodeBase
{
    children?: NodeJson[]
    tags?: String2Record

    visible?: boolean
    childrenVisible?: boolean
    selected?: boolean
    completion?: number
}

export interface TabJson
{
    rootNode: NodeJson
    camera: SimpleCamera
}

export interface ProjectJson
{
    indexOfSelectedTab: number
    tabs: TabJson[]
    styles: StyleJson[]
    config: ProjectConfigJson
}

export interface AppFile
{
    mimeType: string,
    size: string,
    id: string,
    name: string,
    modifiedTime: string,
    parents: string[],
}

export interface SimpleTag
{
    readonly name: string,
    value: string,
}