import { writable } from "svelte/store"
import type { Pos } from "../util/interfaces"
import { HtmlComp } from "../util/classes/HtmlComp"

export class SvelteCircle extends HtmlComp
{
    public goalPos: Pos
    public size: number
    // public visible: boolean = userConfig.get("DEBUG")
    private _visible: boolean = true

    get visible(): boolean
    {
        return this._visible
    }

    set visible(value: boolean)
    {
        this.setVisible(value)
    }

    constructor(goalPos: Pos, size: number, public color: string = "red")
    {
        super()
        this.goalPos = goalPos
        this.size = size
    }

    moveTo(pos: Pos, center: boolean = true)
    {
        this.moveToCoords(pos.x, pos.y, center)
    }

    moveToCoords(x: number, y: number, center: boolean = true)
    {
        this.goalPos.x = x
        this.goalPos.y = y

        //animate?
        this.el.style.transform = `translate(${x - (center ? this.size / 2 : 0)}px, ${y - (center ? this.size / 2 : 0)}px)`
    }

    setVisible(visible: boolean)
    {
        this._visible = visible
        if(this.el != null)
        {
            this.el.style.display = visible ? "block" : "none"
        }
    }
}

export const pointerCircle = new SvelteCircle({ x: 0, y: 0 }, 16, "white")
export const debugCircle = new SvelteCircle({ x: 0, y: 0 }, 64, "red")
export const moveNodeIndicatorCircle = new SvelteCircle({ x: 0, y: 0 }, 32, "lime")

export const circles = writable<SvelteCircle[]>
([
    pointerCircle,
    debugCircle,
    moveNodeIndicatorCircle,
])