<script lang="ts">
import PanelComp from "./PanelComp.svelte";
import ItemsPanelComp from "./ItemsPanelComp.svelte";
import { Tag } from "../../comps_data/tags.svelte";
import { addAllFromTo, appendObjArray, forEachTag, getOrCreateObj, log } from "../../util/util.svelte";
import { untrack } from "svelte";
import TagComp from "./../TagComp.svelte";
import type { NodeData } from "../../comps_data/node_data.svelte";
import { get } from "svelte/store";
import { currentTab } from "../../comps_data/tabs.svelte";
import { waitTick } from "../../comps_data/app.svelte";
import { HACK_WAIT_MS } from "../../data/finals";
import { createTag } from "../../comps_data/nodes.svelte";

let
{
    nodes,
}:
{
    nodes: NodeData[],
} = $props()

type ValuesNodesObj = {[key: string]: NodeData[]}
type NamesValuesNodesObj = {[key: string]: ValuesNodesObj}
type NodesTagObj =
{
    previewTag: Tag,
    nodes: NodeData[],
}

const individualTags: Tag[] = []
const uniqueTagsNamesSet: Set<string> = new Set()
let previewTags: NodesTagObj[] = $state([])

$effect(() =>
{
    nodes.length
    nodes

    untrack(() =>
    {
        updateTags()
    })
})

function updateTags()
{
    uniqueTagsNamesSet.clear()
    individualTags.length = 0
    const groupedTags: NamesValuesNodesObj = {}

    forEachTag(nodes, (tag, node) =>
    {
        individualTags.push(tag)
        const valuesMap: ValuesNodesObj = getOrCreateObj(groupedTags, tag.name, () => ({}))
        appendObjArray(valuesMap, tag.getValue(), node)
        uniqueTagsNamesSet.add(tag.name)
    })

    const newPreviewTags: NodesTagObj[] = []

    for(const [name, ValuesNodesObj] of Object.entries(groupedTags))
    {
        for(const [value, nodes] of Object.entries(ValuesNodesObj))
        {
            const previewTag = new Tag(name, value)
            
            newPreviewTags.push({ previewTag, nodes })
        }
    }

    previewTags = newPreviewTags
}

function updateTree()
{
    const tab = get(currentTab)
    
    setTimeout(() =>
    {
        tab.update(true)
    }, HACK_WAIT_MS)
}

function createTagInternal()
{
    addAllFromTo(createTag(nodes), individualTags)

    updateTree()
}
</script>

<PanelComp>
    <ItemsPanelComp
        items={previewTags}
        onItemPicked={(data) => console.log(data)}
        // createNewInputs={{ "name": "New Tag" }}
        createNew={nodes.length == 0 ? null! : () => createTagInternal()}
        onDelete={(data, i) =>
        {
            const name = data.previewTag.name
            const value = data.previewTag.value

            for(const node of nodes)
            {
                if(!node.hasTag(name) || node.getTagValue(name) != value)
                {
                    continue
                }

                node.deleteTag(name)

                updateTree()
                waitTick(1, () => updateTags())
            }
        }}
        >
        {#snippet  header()}
            <div class="centered_text">
                {#if nodes.length > 0}
                    {`~[${nodes.length}] Nodes~`}
                {:else}
                    Select Some Nodes First~!
                {/if}
            </div>
        {/snippet}
        {#snippet itemSnippet(data)}
            <div class="flex_horizontal">
                <div>[{data.nodes.length}]x</div>
                <TagComp
                    editable={true}
                    tag={data.previewTag}
                    onNameChange={newName =>
                    {
                        const oldName = data.previewTag.name
                        const value = data.previewTag.value

                        for(const node of nodes)
                        {
                            if(!node.hasTag(oldName) || node.getTagValue(oldName) != value)
                            {
                                continue
                            }

                            if(node.hasTag(newName))
                            {
                                log(`Node "${node.formattedText}" already has tag with name "${newName}"~!`)
                                continue
                            }
                            node.deleteTag(oldName)
                            node.setTag(newName, data.previewTag.value)
                        }
                        
                        waitTick(1, () => updateTags())
                    }}
                    onValueChange={newValue =>
                    {
                        const name = data.previewTag.name
                        const oldValue = data.previewTag.value

                        for(const node of nodes)
                        {
                            if(node.getTagValue(name) != oldValue)
                            {
                                continue
                            }

                            node.setTag(name, newValue)
                        }

                        waitTick(1, () => updateTags())
                    }}
                    />
            </div>
        {/snippet}
    </ItemsPanelComp>
</PanelComp>

