<script lang="ts">
import NodeComp from "./NodeComp.svelte";
import { Node, shouldSelectParentNodeOnElClick } from "../comps_data/nodes.svelte";
import { SHOW_HIDE_TOGGLE_SIZE, SHOW_HIDE_TOGGLE_SIZE_HALF } from "../data/finals";
import { projectConfig } from "../data/projectConfig";
import TagComp from "./TagComp.svelte";
import { getEventTargetNode, mapCapped } from "../util/util.svelte";
import CheckboxComp from "./CheckboxComp.svelte";
import BoundaryComp from "./BoundaryComp.svelte";
import { dev, modifierStates } from "../comps_data/app.svelte";
import InputLabelComp from "./InputLabelComp.svelte";

// export let node: Node

let
{
    node,
    withChildren = false,
    editable = false,
    reactiveOpacity = false,
    mainEl = false,
    selectedOverride = undefined,
    position = "relative",
} :
{
    node: Node
    withChildren?: boolean
    editable?: boolean
    position?: "absolute" | "relative"
    reactiveOpacity?: boolean
    mainEl?: boolean
    selectedOverride?: (node: Node) => boolean
} = $props()
// export let node: Node

// console.log(`node: ${typeof(node)}`)
// console.log(node)

//region onDoubleClick
function onDoubleClick(e: MouseEvent)
{
    if(!editable)
    {
        return
    }

    const [node, depth, els] = getEventTargetNode(e)

    if(node == null)
    {
        return
    }

    if(node.editing)
    {
        return
    }

    const clickedEl = els[0]

    if(!shouldSelectParentNodeOnElClick(clickedEl))
    {
        return
    }

    node.startEditing()
}

function bindThisEl(el: HTMLElement)
{
    if(!mainEl)
    {
        return
    }

    node.setThisEl(el)
}

function bindInputLabelEls(textEl: HTMLTextAreaElement, labelEl: HTMLDivElement)
{
    if(!mainEl)
    {
        return
    }

    // console.log(`bindInputLabelEls: ${textEl}, ${labelEl}`)
    node.textEl = textEl
    node.labelEl = labelEl
}

function onMouseDown(e: MouseEvent)
{
    switch(e.button)
    {
        case 2:
        {
            if(!node.selected)
            {
                node.tab.selectNodes(node, true)
            }
            node.tab.openNodesContextMenu(e.clientX, e.clientY)

            e.stopPropagation()
        }
        break
    }
}
</script>

<!-- svelte-ignore a11y_no_static_element_interactions -->
<div class="node"
    use:bindThisEl

    ondblclick={onDoubleClick}
    onmousedown={onMouseDown}

    data-id={node.id}
    tabindex=0
    role="button"

    //#region style
    style:position={position}
    style:left="{position == "absolute" ? node.pos.x : 0}px"
    style:top="{position == "absolute" ? node.pos.y : 0}px"
    style:display="{node.visible ? 'flex' : 'none'}"
    style:opacity={reactiveOpacity ? node.opacity : 1}
    style:max-width={node.style.get("nodeMaxWidth") + "px"}
    style:max-height={node.style.get("nodeMaxHeight") + "px"}

    // style:left="{node.pos.x}px"
    // style:top="{node.pos.y}px"

    style:min-width="{projectConfig.get("NODE_MIN_WIDTH")}px"
    style:min-height="{projectConfig.get("NODE_MIN_HEIGHT")}px"
    style:outline=none
    
    style:background={node.getDynamicColor(undefined, undefined, node.selected ? 0.5 : 0, node.selected ? 0.05 : 0)}

    style:pointer-events={node.alive ? 'auto' : 'none'}
    // style:z-index={node.getZIndex()}
    //#endregion style
>
    {#if dev}
		<!-- d{node.getDynamicIndex()}: {node.style.getDynamicHue(node.getDynamicIndex())} -->
		<!-- | {node.style == Style.DEFAULT} -->
		<!-- | n{node.id} | nd{node.data.id} -->
		<!-- {#if node.mimickedBy.size > 0}
			mimickedBy:{Array.from(node.mimickedBy.values()).map(n => n.id).join(", ")}
		{/if} -->
		<!-- mimicOf:{node.mimicOf?.id ?? "x"} -->
		<!-- | {node.identityTheftTarget?.id ?? "x"} -->
		<!-- e: {node.editing} -->
    {/if}
    <div class="completion_div">
        <CheckboxComp
            value={node.data.isCompleted()}

            index={node.getDynamicIndex()}
            style={node.style}

            // backgroundHueOffset={0}
            backgroundSaturationOffset={node.getSaturationOffset()}
            backgroundLightnessOffset={node.getLightnessOffset()}

            // checkmarkHueOffset={0}
            checkmarkSaturationOffset={0.5}
            checkmarkLightnessOffset={0.25}

            onToggle={(newState) =>
            {
                const newValue = newState ? 1 : 0

                if(modifierStates[0] || modifierStates[1])
                {
                    if(modifierStates[1])
                    {
                        node.toggleCompletionRecursive(true)
                    }
                    else
                    {
                        node.setCompletionRecursive(newValue, true)
                    }
                }
                else
                {
                    node.data.setCompletion(newValue, true)
                }
            }}
        />
    </div>

    <div class="node_content">
        {#if withChildren}
            {#if node._opacity > 0}
                {#if node.children.length > 0}
                <BoundaryComp
                    style={node.style}
                    index={node.getDynamicIndex()}
                    opacity={node.opacity * mapCapped(Math.max(node.totalHeight, node.totalWidth), 500, 2000, 0.1, 0.03)}
                    // opacity={node.opacity}
                    rect=
                    {new DOMRect
                    (
                        0,
                        -node.halfTotalHeight + node.halfHeight,
                        node.totalWidth,
                        node.totalHeight,
                    )}
                    />
                {/if}
            {/if}

            <!-- parent line -->
            <!-- direct line -->
            {#if node.lineToParentNode != null}
            <svg 
                style="position: absolute; left: 0; top: 0; pointer-events: none; overflow: visible;"
            >
                <line
                    style:display={node.lineToParentNode.alive ? 'block' : 'none'}
                    x1={node.lineToParentPos1.x}
                    y1={node.lineToParentPos1.y}
                    x2={node.lineToParentPos2.x}
                    y2={node.lineToParentPos2.y}
                    style:stroke={node.lineStroke}
                    style:background={node.backgroundColor}
                    stroke-width="3"
                />
            </svg>
            {/if}

        <!-- show/hide toggle -->
        <!-- svelte-ignore binding_property_non_reactive -->
            {#if node.anyChildrenAlive}
                <button class="showHideToggle"
                    tabindex=-1
                    style:opacity={node.showHideToggleOpacity}
                    onmouseenter={(e) =>
                    {
                        node.hovered = true
                    }}
                    onmouseleave={(e) =>
                    {
                        node.hovered = false
                    }}
                    style:display={node.alive && !node.editing ? 'block' : 'none'}
                    style:width={`${SHOW_HIDE_TOGGLE_SIZE}px`}
                    style:height={`${SHOW_HIDE_TOGGLE_SIZE}px`}
                    style:left={`${node.size.x}px`}
                    style:top={`${(node.size.y/2) - SHOW_HIDE_TOGGLE_SIZE_HALF}px`}
                    style:color="black"
                    style:background={node.childrenVisible ? 'white' : 'grey'}
                    // style:border-color={node.showChildren ? 'white' : 'grey'}
                    onclick={() =>
                    {
                        node.toggleChildrenVisible()
                    }}
                >
                    {node.childrenVisible ? "-" : "+"}
                </button>
            {/if}

            <!-- children -->
            {#if node.childrenVisible}
                {#each node.children as childSvelteNode (childSvelteNode.id)}
                    <NodeComp
                        editable={editable}
                        withChildren={withChildren}
                        reactiveOpacity={reactiveOpacity}
                        node={childSvelteNode}
                        mainEl={mainEl}
                        position=absolute
                    />
                {/each}
            {/if}
        {/if}

        <InputLabelComp
            onInput={(event, target) => node.onInput(target)}
            onBlur={(event, text) =>
            {
                node.stopEditing(true)
            }}

            editing={node.editing}
            startEditingOnDoubleClick={false}

            style={node.style}
            index={node.getDynamicIndex()}

            value={node.data.text}
            labelValue={node.data.formattedText}

            onElementsBound={(textEl, labelEl) => bindInputLabelEls(textEl, labelEl)}
            />

        <!-- region tags -->
        {#if node.data.tagsComps.length > 0}
            <div class="tags"
            style:color={node.getStyleValue("textColor")}
            style:-webkit-text-stroke={`${node.style.get("textOutlineSize")} ${node.getStyleValue("textOutlineColor")}`}

                style:max-width={node.style.get("nodeMaxWidth") + "px"}
            >
                {#each node.data.tagsComps as tag (tag.id)}
                    <TagComp
                        onlyDisplayValueIfNotEmpty={true}
                        tag={tag}
                    />
                {/each}
            </div>
        {/if}
        <!-- endregion tags -->
    </div>
</div>

<style>
.completion_div
{
    align-items:start;
    padding: 8px;
}

.node
{
    background: pink;

    border-radius: 8px;
    padding: 8px;

    align-items: center;

    display: flex;
    flex-direction: row;

    width: max-content;
    pointer-events: auto;
}

.node_content
{
    align-items: flex-start;
    justify-content: center;

    display: flex;
    flex-direction: column;

    width: max-content;
}

.showHideToggle
{
    position: absolute;
    border-radius: 50%;
    background: transparent;
    pointer-events: auto;
    opacity: 0%;
}

.tags
{
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    align-self: center;
    gap: 2px;

    left: 0;
    top: 100%;
    margin: 2px;
}
</style>