<script lang="ts">
    import type { Snippet } from "svelte";
    import ButtonComp from "./../ButtonComp.svelte";
    import ItemsPanelComp from "./ItemsPanelComp.svelte";
    import type { TitleAction } from "../../comps_data/app.svelte";
    import { Style } from "../../data/styles";

    let
    {
        items,
        header,
        footer,
        afterItemClicked,
        style = Style.DEFAULT,
        flexDirection = "column",
        selected,
        createNew,
        buttonWidth = "100%",
    }:
    {
        items: TitleAction[]
        header?: Snippet
        footer?: Snippet
        onClose?: () => void
        afterItemClicked?: (item: TitleAction) => void
        style?: Style,
        flexDirection?: "column" | "row"
        selected?: (item: TitleAction) => boolean
        createNew?: () => TitleAction | void
        buttonWidth?: string
    } = $props()
</script>

<ItemsPanelComp
    header={header}
    footer={footer}
    flexDirection={flexDirection}
    items={items}
    createNew={createNew}
    onItemPicked={(data) =>
    {
        data.action(data)
        afterItemClicked?.(data)
    }}
    >
    {#snippet itemSnippet(data, index)}
        <div
            class="row item_row"
            >
            <ButtonComp
                style={style}
                index={index}
                title={data.title}
                width={buttonWidth}
                extraClass="full_width"
                selected={selected == null ? undefined : selected(data)}
            />
        </div>
    {/snippet}
</ItemsPanelComp>

<style>
.item_row
{
    width: 100%;
    pointer-events: auto;
    padding: 2px;
}
</style>