import { get, writable } from "svelte/store"
import { setAppFiles } from "../../../comps_data/app.svelte"
import { messages } from "../../../comps_data/messages.svelte"
import { APP_NAME, EMPTY_ARRAY, GOOGLE_CLIENT_ID, MIMETYPE_GOOGLE_DRIVE_FOLDER } from "../../../data/finals"
import type { GoogleIdentity, TokenClient } from "../../../types/google.indentity"
import type { AppFile } from "../../../util/interfaces"
import { errorToString } from "../../../util/util.svelte"

let google: GoogleIdentity = null!
let tokenClient: TokenClient = null!

const ACCESS_TOKEN = "google_drive_access_token"
const ACCESS_TOKEN_INVALID_AFTER = "google_drive_access_token_invalid_after"

let accessTokenPromise: Promise<string> = null!
let accessTokenPromiseResolve: (value: string) => void = null!

export let currentGoogleDriveFolderId = writable<string>(null!)
export let currentGoogleDriveParents = writable<string[]>([])
export const googleDriveParentsMap: Map<string, string[]> = new Map()

export function registerGoogleDriveParents(fileId: string, parents: string[])
{
    googleDriveParentsMap.set(fileId, parents)
}

function initGoogleAuth()
{
    console.log("Initialized Google authentication")

    tokenClient = google.accounts.oauth2.initTokenClient
    ({
        client_id: GOOGLE_CLIENT_ID,
        scope: "https://www.googleapis.com/auth/drive",
        callback: (res) =>
        {
            console.log("callback")

            if(res.error)
            {
                const text = `(2/2) Error requesting Google access token:\n${res.error}\n${res.error_description}`
                console.error(text)
                messages.addErrorMessage(text)

                accessTokenPromiseResolve(null!)
                accessTokenPromiseResolve = null!
                return
            }

            console.log("(2/2) Received Google access token!")
            
            setAccessToken(res.access_token)
            const expiresIn = (res.expires_in ?? 3600) * 1000
            const expiredAfter = Date.now() + expiresIn
            localStorage.setItem(ACCESS_TOKEN_INVALID_AFTER, expiredAfter.toString())

            accessTokenPromiseResolve(res.access_token)
            accessTokenPromiseResolve = null!
        }
    })
}

function setAccessToken(token: string)
{
    localStorage.setItem(ACCESS_TOKEN, token)
}

export function isGoogleDriveAccessTokenValid(): boolean
{
    const accessToken = localStorage.getItem(ACCESS_TOKEN)

    if(accessToken == null)
    {
        return false
    }

    const invalidAfter = localStorage.getItem(ACCESS_TOKEN_INVALID_AFTER)

    if(invalidAfter == null)
    {
        return false
    }

    return Date.now() < parseInt(invalidAfter)
}

async function getAccessToken()
{
    if(isGoogleDriveAccessTokenValid())
    {
        return localStorage.getItem(ACCESS_TOKEN)
    }

    // if(!canOpenWindow())
    // {
    //     messages.addWarningMessage("Cannot request Google access token because Noded is not allowed to open a new window!")
    //     return null!
    // }

    console.log("(1/2) Requesting Google access token...")
    accessTokenPromise = new Promise((resolve) =>
    {
        accessTokenPromiseResolve = resolve
    })

    tokenClient.requestAccessToken({ prompt: "consent" })

    return accessTokenPromise
}

export async function saveJsonToGoogleDrive(fileName: string, content: string, fileId?: string): Promise<Response>
{
    try
    {
        let message = `Saving "${fileName}" to Google Drive...`
        console.log(`(1/2) ${message}`)
        messages.addMessage(message)

        const result = await uploadJsonFileToGoogleDrive(fileName, content, fileId)
    
        message = `Finished saving "${fileName}" to Google Drive!`
        console.log(`(2/2) ${message}`)
        messages.addSuccessMessage(message)

        return result
    }
    catch(e)
    {
        const text = `Error saving to Google Drive:\n${errorToString(e)}`
        console.error(text)
        messages.addErrorMessage(text)
    }

    return null!
}

let googleInitialized = false

export function isGoogleInitialized()
{
    return googleInitialized
}

export async function initializeGoogle()
{
    return new Promise<void>((resolve) =>
    {
        const check = () =>
        {
            console.log("(1/2) Checking for Google API...")

            if(window.google != null)
            {
                google = window.google

                if(google.accounts != null)
                {
                    console.log("(2/2) Google API loaded!")
                    googleInitialized = true
                    initGoogleAuth()
                    resolve()
                    return
                }
            }

            setTimeout(check, 100)
        }

        check()
    })
}

export let googleDriveAppFolderId: string = null!

export async function createGoogleDriveAppFolderSoft(): Promise<string>
{
    if(googleDriveAppFolderId != null)
    {
        return googleDriveAppFolderId
    }

    const accessToken = await getAccessToken()

    if(accessToken == null)
    {
        return null!
    }

    const folderName = APP_NAME

    const searchQ = `name='${APP_NAME}' and mimeType='application/vnd.google-apps.folder' and 'root' in parents and trashed=false`

    console.log(`(1/2) Searching for existing "${APP_NAME}" in Google Drive...`)

    const headers = await getHeaders()

    const searchRes = await fetch
    (
        `https://www.googleapis.com/drive/v3/files?` +
        `q=${encodeURIComponent(searchQ)}&fields=files(id,modifiedTime)`,
        { headers }
    )

    const searchJson = await searchRes.json()

    if("files" in searchJson)
    {
        const files = searchJson.files as { id: string, modifiedTime: string }[]

        if(files.length > 0)
        {
            if(files.length > 1)
            {
                //Sort oldest first at [0]
                files.sort((a, b) => new Date(a.modifiedTime).getTime() - new Date(b.modifiedTime).getTime())
                
                console.warn(`Found multiple "${APP_NAME}" folders in Google Drive! Using the oldest one found with ID: ${files[0].id} and modified time: ${files[0].modifiedTime}`)
            }

            const folderId = files[0].id

            console.log(`(2/2) Found existing "${APP_NAME}" folder in Google Drive with ID: ${folderId}`)
            googleDriveAppFolderId = folderId

            return folderId
        }
    }

    messages.addMessage(`(1/2) Creating app folder "${APP_NAME}" in Google Drive...`)

    const createRes = await fetch
    (
        "https://www.googleapis.com/drive/v3/files",
        {
            method: "POST",
            headers:
            {
                Authorization: `Bearer ${await getAccessToken()}`,
            },
            body: JSON.stringify
            ({
                name: folderName,
                mimeType: MIMETYPE_GOOGLE_DRIVE_FOLDER
            })
        }
    )

    const data = await createRes.json()

    messages.addSuccessMessage(`Created app folder "${folderName}" in Google Drive!`)

    return data.id
}

async function getHeaders()
{
    const accessToken = await getAccessToken()

    if(accessToken == null)
    {
        return null!
    }

    return {
        Authorization: `Bearer ${accessToken}`
    }
}

async function overwriteGoogleDriveFile
(
    fileId: string,
    content: string,
): Promise<Response>
{
    const headers = await getHeaders()

    const response = await fetch
    (
        `https://www.googleapis.com/upload/drive/v3/files/${fileId}?uploadType=media`,
        {
            method: 'PATCH',
            headers:
            {
                ...headers,
                // 'Content-Type': 'application/json',
            },
            body: content
        }
    )

    if (!response.ok)
    {
        throw new Error(await response.text())
    }

    return response
}

async function uploadJsonFileToGoogleDrive(name: string, content: string, fileId?: string): Promise<Response>
{
    if(fileId != null && fileId.length > 0)
    {
        const exists = await googleDriveFileExists(fileId)

        if(exists)
        {
            return overwriteGoogleDriveFile(fileId, content)
        }
    }

    const folderId = await createGoogleDriveAppFolderSoft()

    const metadata =
    {
        name: `${name}.json`,
        parents: [folderId]
    }

    const form = new FormData()

    form.append("metadata", new Blob([JSON.stringify(metadata)],
    {
        type: "application/json"
    }))

    form.append("file", new Blob([content],
    {
        type: "application/json"
    }))

    const headers = await getHeaders()

    return fetch
    (
        "https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart",
        {
            method: "POST",
            headers,
            body: form
        }
    )
}

export async function googleDriveFileExists(fileId: string): Promise<boolean>
{
    const headers = await getHeaders()

    const res = await fetch
    (
        `https://www.googleapis.com/drive/v3/files/${fileId}?fields=id,trashed`,
        { headers }
    )

    if (res.ok)
    {
        const json = await res.json()

        if(json.trashed)
        {
            return false
        }

        return true
    }

    if (res.status === 404)
    {
        return false
    }

    throw new Error(await res.text())
}

export async function downloadGoogleDriveFile(fileId: string): Promise<Response>
{
    try
    {
        const headers = await getHeaders()

        if(headers == null)
        {
            return null!
        }
    
        const res = await fetch
        (
            `https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`,
            {
                headers,
            }
        )
    
        return res.json()
    }
    catch(e)
    {
        const text = `Error downloading from Google Drive:\n${errorToString(e)}`

        console.error(text)
        messages.addErrorMessage(text)
    }

    return null!
}

export async function getGoogleDriveFolderFiles(folderId: string)
{
    try
    {
        if(folderId == null)
        {
            folderId = await createGoogleDriveAppFolderSoft()
        }
        else
        {
            await getAccessToken()
        }

        const headers = await getHeaders()

        let url = `https://www.googleapis.com/drive/v3/files`

        const q = `'${folderId}' in parents and trashed = false`

        url += `?q=${encodeURIComponent(q)}`

        url += `&supportsAllDrives=true&includeItemsFromAllDrives=true`
        url += `&fields=files(id,name,size,mimeType,modifiedTime,parents)`

        const res = await fetch
        (
            url,
            { headers }
        )

        const json = await res.json()

        const files: AppFile[] = json.files

        // for(const file of files)
        // {
        //     console.log(file)
        // }

        return files
    }
    catch(e)
    {
        const text = `Error listing Google Drive files:\n${errorToString(e)}`

        console.error(text)
        messages.addErrorMessage(text)
    }
}

let googleDriveQueryPromise: Promise<any> = null!

export function isGoogleDriveQueryInProgress()
{
    return googleDriveQueryPromise != null
}

export function setGoogleDriveQueryPromise<T>(promise: Promise<T>): Promise<T>
{
    googleDriveQueryPromise = promise

    if(promise != null)
    {
        promise.finally(() => googleDriveQueryPromise = null!)
    }

    return promise
}

export async function setAppFilesToGoogleDriveFolder(folderId: string = get(currentGoogleDriveFolderId))
{
    currentGoogleDriveFolderId.set(folderId)

    const files = await getGoogleDriveFolderFiles(folderId)

    if(files == null)
    {
        return EMPTY_ARRAY as AppFile[]
    }

    setAppFiles(files)

    currentGoogleDriveParents.set(googleDriveParentsMap.get(folderId) ?? [])

    return files
}