<script lang="ts">
    import type { Snippet } from "svelte";
    import type { AppFile } from "../../util/interfaces";
    import PanelComp from "./PanelComp.svelte";
    import FilesPanelComp from "./FilesPanelComp.svelte";
    import ButtonsPanelComp from "./ButtonsPanelComp.svelte";
    import { sIfNot1 } from "../../util/util.svelte";

    let
    {
        parents,
        items,
        onParentPicked,
        onItemPicked,
        header,
        footer,
    }:
    {
        parents?: string[]
        items: AppFile[]
        onParentPicked: (id: string, index: number) => void
        onItemPicked: (item: AppFile, index: number) => void
        header?: Snippet
        footer?: Snippet
    } = $props()
</script>

<PanelComp
header={header}
footer={footer}
    >
    {#if parents != null && parents.length > 0}
    <ButtonsPanelComp
        items={parents.map((folderId, i) => ({title: `⬆️ Go Back`, action: () => onParentPicked(folderId, i)}))}
    >
    </ButtonsPanelComp>
    {/if}
    <FilesPanelComp
        items={items}
        onItemPicked={onItemPicked}
    >
    {#snippet footer()}
        <div
            class="centered_text"
            >
            ~{items.length} item{sIfNot1(items.length)} found~
        </div>
        {@render footer?.()}
    {/snippet}
    </FilesPanelComp>
</PanelComp>