export function getNodeFromHTMLElement(el: HTMLElement, recursive: boolean = true, els: HTMLElement[] = [], depth: number = 0): MouseEventTargetResult
{
    if(el == null)
    {
        return [null!, depth, els]
    }

    els.push(el)

    const data = el.dataset

    let foundNode = false

    if("id" in data)
    {
        const id: string = data.id as string
        
        const node = getNodeById(parseInt(id))

        if(node != null)
        {
            foundNode = true

            if(node.alive)
            {
                return [node, depth, els]
            }
        }
    }

    if(foundNode)
    {
        //Found node but didn't qualify
        return [null!, depth, els]
    }
    
    if(recursive)
    {
        return getNodeFromHTMLElement(el.parentElement!, recursive, els, depth + 1)
    }
    else
    {
        return [null!, depth, els]
    }
}

export function getEventTargetNode(e: Event, recursive: boolean = true): MouseEventTargetResult
{
    const target = e.target

    if(!(target instanceof HTMLElement))
    {
        return [null!, -1, []]
    }
    
    return getNodeFromHTMLElement(target, recursive)
}

export function isWithinRect(x: number, y: number, x1: number, y1: number, x2: number, y2: number): boolean
{
    const   left = Math.min(x1, x2)
    const  right = Math.max(x1, x2)
    const    top = Math.min(y1, y2)
    const bottom = Math.max(y1, y2)

    const inside = left <= x && x <= right && top <= y && y <= bottom

    return inside
}

export function areRectsOverlappingObj(r1: DOMRect, r2: DOMRect): boolean
{
    return areRectsOverlapping(r1.x, r1.y, r1.x + r1.width, r1.y + r1.height, r2.x, r2.y, r2.x + r2.width, r2.y + r2.height)
}

export function areRectsOverlappingRawObj(r1pos1: Pos, r1pos2: Pos, r2: DOMRect)
{


    return areRectsOverlapping
        (
            r1pos1.x,
            r1pos1.y,
            r1pos2.x,
            r1pos2.y,
            r2.x,
            r2.y,
            r2.x + r2.width,
            r2.y + r2.height
        )
}

export function areRectsOverlapping
(
    r1x1: number,
    r1y1: number,
    r1x2: number,
    r1y2: number,
    r2x1: number,
    r2y1: number,
    r2x2: number,
    r2y2: number,
): boolean
{
    return (
        (isWithinRange(r1x1, r2x1, r2x2) || isWithinRange(r1x2, r2x1, r2x2))
        &&
        (isWithinRange(r1y1, r2y1, r2y2) || isWithinRange(r1y2, r2y1, r2y2))
    )
    ||
    (
        (isWithinRange(r2x1, r1x1, r1x2) || isWithinRange(r2x2, r1x1, r1x2))
        &&
        (isWithinRange(r2y1, r1y1, r1y2) || isWithinRange(r2y2, r1y1, r1y2))
    )
}

export function stringify(obj: any): string
{
    return JSON.stringify(obj, null, "\t").replace(/: ([{\[])\n([\t]*)\t/g, ":\n$2$1\n$2\t")
}

export function wrapIndex(thisIndex: number, offset: number, length: number): number
{
    return ((thisIndex + offset) % length + length) % length
}

export function getWrapped<T>(array: T[], index: number, offset: number = 0): T
{
    return array[wrapIndex(index, offset, array.length)]
}

