export function getHalfWidth(rect: DOMRect): number
{
    return rect.width / 2
}

export function getHalfHeight(rect: DOMRect): number
{
    return rect.height / 2
}

export function getRectPoint(rect: DOMRect, pos: Direction2D9): Pos
{
    switch(pos)
    {
        case Direction2D9.TopLeft     : return { x: rect.left                     , y: rect.top                       }
        case Direction2D9.Top         : return { x: rect.left + getHalfWidth(rect), y: rect.top                       }
        case Direction2D9.TopRight    : return { x: rect.left + rect.width        , y: rect.top                       }
        case Direction2D9.Left        : return { x: rect.left                     , y: rect.top + getHalfHeight(rect) }
        case Direction2D9.Center      : return { x: rect.left + getHalfWidth(rect), y: rect.top + getHalfHeight(rect) }
        case Direction2D9.Right       : return { x: rect.left + rect.width        , y: rect.top + getHalfHeight(rect) }
        case Direction2D9.BottomLeft  : return { x: rect.left                     , y: rect.top + rect.height         }
        case Direction2D9.Bottom      : return { x: rect.left + getHalfWidth(rect), y: rect.top + rect.height         }
        case Direction2D9.BottomRight : return { x: rect.left + rect.width        , y: rect.top + rect.height         }
    }
}
