export function isWithinRangeOf(value: number, target: number, range: number): boolean
{
    return isWithinRange(value, target - range, target + range)
}

export function getMouseWheelEventDirection(e: WheelEvent): Direction2D4
{
    // log(`deltaX: ${e.deltaX}, deltaY: ${e.deltaY}`)

    if(Math.abs(e.deltaX) < Math.abs(e.deltaY))
    {
        if(e.deltaY < 0)
        {
            return Direction2D4.Up
        }
        else
        {
            return Direction2D4.Down
        }
    }
    else
    {
        if(e.deltaX < 0)
        {
            return Direction2D4.Left
        }
        else
        {
            return Direction2D4.Right
        }
    }
}

export function getOrCreateMap<K, V>(map: Map<K, V>, key: K, createValue: () => V): V
{
    let value = map.get(key)

    if(value == null)
    {
        value = createValue()
        map.set(key, value)
    }

    return value
}

export type ObjKey = string | number | symbol

export function getOrCreateObj<V>(obj: {[key: ObjKey]: V}, key: ObjKey, ifNullMaker: () => V): V
{
    if(obj[key] == null)
    {
        obj[key] = ifNullMaker()
    }
    return obj[key]
}

export function appendObjArray<V>(obj: {[key: ObjKey]: V[]}, key: ObjKey, item: V): V[]
{
    let array = obj[key]
    if(array == null)
    {
        array = []
        obj[key] = array
    }
    array.push(item)

    return array
}

export function incrementMapSoft<K, V>(map: Map<K, number>, key: K, incrementBy: number = 1): number
{
    let value = map.get(key)

    if(value == null)
    {
        map.set(key, incrementBy)
        value = incrementBy
    }

    return incrementBy
}

export function incrementRecordSoft<K extends string | number | symbol, V>(map: Record<K, number>, key: K, incrementBy: number = 1): number
{
    let value = map[key]

    if(value == null)
    {
        map[key] = incrementBy
        value = incrementBy
    }

    return incrementBy
}

export function scaleRect(rect: DOMRect, scale: number)
{
    rect.x *= scale
    rect.y *= scale
    rect.width *= scale
    rect.height *= scale
}

