export function addAllFromTo<T, C extends Array<T> | Set<T>>(items: Iterable<T>, collection: C)
{
    for (const item of items)
    {
        if (collection instanceof Array)
        {
            collection.push(item)
        }
        else if (collection instanceof Set)
        {
            collection.add(item)
        }
    }
}

export function softToFixed(num: number, maxDecimals: number = 2): string
{
    if (!isFinite(num))
    {
        return String(num)
    }
    const factor = Math.pow(10, maxDecimals)
    const rounded = Math.round(num * factor) / factor
    return rounded.toString()
}

export function toStamp(toStamp: number): string
{
    if(isNaN(toStamp) || toStamp == Infinity || toStamp == -Infinity)
    {
        toStamp = 0
    }

    let stamped: string = ''
    toStamp = Math.floor(toStamp)
    let negative = false
    if(toStamp < 0)
    {
        toStamp = -toStamp
        negative = true
    }
    if (Math.floor(toStamp/3600) >= 24)
    {
        if (Math.floor(toStamp/3600) < 48)
            stamped += `[${Math.floor(toStamp/86400)}] day, `
        else
            stamped += `[${Math.floor(toStamp/86400)}] days, `
    }
    stamped += 
        '[' +
            Math.floor(toStamp % 86400 / 3600) + '\:' + 
            (Math.floor(toStamp % 3600 / 60) > 9 ? Math.floor(toStamp % 3600 / 60) : ('0' + Math.floor(toStamp % 3600 / 60))) + '\:' +
            (Math.floor(toStamp % 60) > 9 ? toStamp % 60 : '0' + toStamp % 60) +
        ']'
    if(negative)
        return `-${stamped}`
    else
        return stamped
}

export function normalizeVec2(pos: Pos): Pos
{
    const length = Math.sqrt(pos.x * pos.x + pos.y * pos.y)
    
    if(length == 0)
    {
        return { x: 0, y: 0 }
    }

    return {
        x: pos.x / length,
        y: pos.y / length,
    }
}

export function xmur3(str: string)
{
    let h = 1779033703 ^ str.length

    for(let i = 0; i < str.length; i++)
    {
        h = Math.imul(h ^ str.charCodeAt(i), 3432918353)
        h = h << 13 | h >>> 19
    }

    return function()
    {
        h = Math.imul(h ^ h >>> 16, 2246822507)
        h = Math.imul(h ^ h >>> 13, 3266489909)

        return (h ^= h >>> 16) >>> 0
    }
}

export function mulberry32String(seed: string, asInt: boolean = true)
{
    return mulberry32(xmur3(seed)(), asInt)
}

export function mulberry32(seed: number, asInt: boolean = true)
{
    return function()
    {
        let t = seed += 0x6D2B79F5

        t = Math.imul(t ^ t >>> 15, t | 1)
        t ^= t + Math.imul(t ^ t >>> 7, t | 61)

        return ((t ^ t >>> 14) >>> 0) / (asInt ? 1 : 4294967296)
    }
}

export function getLast<T>(array: T[]): T
{
    return array[array.length - 1]
}

export function getLastChar(text: string): string
{
    return text.charAt(text.length - 1)
}

export function addAllFromToWritable<V, C extends Array<V>>(writable: Writable<C>, items: C | V)
{
    writable.update(current =>
    {
        if(Array.isArray(items))
        {
            addAllFromTo(items, current)
        }
        else
        {
            current.push(items)
        }

        return current
    })
}

export function getLastFromWritable<V>(writable: Writable<V[]>): V
{
    const items = get(writable)

    return getLast(items)
}

export function softArrayGet<T>(array: T[], index: number): T
