export function clamp(input: number, bound1: number, bound2: number)
{
    if(bound2 < bound1)
    {
        [bound1, bound2] = [bound2, bound1]
    }

    return Math.max(bound1, Math.min(bound2, input))
}

export function map(input: number, min1: number, max1: number, min2: number, max2: number): number
{
    return ((input - min1) / (max1 - min1)) * (max2 - min2) + min2
}

export function mapCapped(input: number, min1: number, max1: number, min2: number, max2: number): number
{
    return clamp(map(input, min1, max1, min2, max2), min2, max2)
}

