export function forEach<T>(items: Iterable<T>, callback: (item: T, index: number) => unknown | boolean, filter?: (item: T, index: number) => boolean)
{
    let i = 0
        for(const item of items)
        {
            if(filter != null)
            {
                if(!filter(item, i))
                {
                    ++i
                    continue
                }
            }

            const result = callback(item, i)
            ++i

            if(result === true)
            {
                break
            }
        }
}

export function forEachArray<T>(array: T[], callback: (item: T, index: number) => unknown | boolean, reversed: boolean = false)
{
    if(reversed)
    {
        for(let i = array.length - 1; i >= 0; --i)
        {
            const result = callback(array[i], i)

            if(result === true)
            {
                break
            }
        }
    }
    else
    {
        for(let i = 0; i < array.length; ++i)
        {
            const result = callback(array[i], i)

            if(result === true)
            {
                break
            }
        }
    }
}

