export async function repeatForMs(action: () => void | boolean, intervalMs: number, maxMs: number, initialWaitMs: number = 0): Promise<boolean>
{
    const startTime = Date.now()

    if(initialWaitMs > 0)
    {
        await waitMs(initialWaitMs)
    }

    while(true)
    {
        const result = action()

        if(result === true)
        {
            return true
        }

        const elapsedTimeMs = Date.now() - startTime

        if(maxMs <= elapsedTimeMs)
        {
            return false
        }

        await waitMs(intervalMs)
    }
}

