export function getNodeData(node: Node | NodeData): NodeData
{
    if(node instanceof Node)
    {
        return node.data
    }

    return node
}

export function deleteFromArray<T>(array: T[], item: T): boolean
{
    const index = array.indexOf(item)

    if(index == -1)
    {
        return false
    }

    array.splice(index, 1)

    return true
}

export function forEachNode(nodes: Iterable<Node>, callback: (node: Node) => void, lastNodeAction?: (lastNode: Node) => void, createCopy: boolean = false)
{
    if(createCopy)
    {
        nodes = [...nodes]
    }

    let lastNode: Node = null!
    for(const node of nodes)
    {
        callback(node)
        lastNode = node
    }
    if(lastNodeAction != null)
    {
        if(lastNode != null)
        {
            lastNodeAction(lastNode)
        }
    }
}

export function getMaxDistanceFromRect(pos: Pos, rect: DOMRect): number
{
    const dx = Math.max(rect.left - pos.x, 0, pos.x - rect.right)
    const dy = Math.max(rect.top - pos.y, 0, pos.y - rect.bottom)

    return Math.max(dx, dy)
}

export function swapArrayElements<T>(array: T[], index1: number, index2: number): void
{
    if(index1 < 0 || index1 >= array.length || index2 < 0 || index2 >= array.length)
    {
        throw new Error(`swapArrayElements: Index out of bounds. Array length: ${array.length}, index1: ${index1}, index2: ${index2}`)
    }

    [array[index1], array[index2]] = [array[index2], array[index1]]
}

export function lerp(start: number, end: number, ratio: number): number
{
    return start + (end - start) * ratio
}

export class RangedNumber
{
    public readonly gap: number

    constructor(readonly minValue: number, readonly maxValue: number)
    {
        this.gap = this.maxValue - this.minValue
    }

    public static ONE = this.value(1)
    public static ZERO = this.value(0)
    public static MINUS_ONE = this.value(-1)
    public static ZERO_TO_ONE = this.range(0, 1)
    public static MINUS_ONE_TO_ONE = this.range(-1, 1)

    public static arrayLimits(array: any[])
    {
        return this.range(0, array.length - 1)
    }

    public static range(minValue: number, maxValue: number)
    {
        return new RangedNumber(minValue, maxValue)
    }

    public static value(value: number)
    {
        return new RangedNumber(value, value)
    }

    public get(): number
    {
        return random(this.minValue, this.maxValue)
    }

    public getInt(): number
    {
        return randomInt(this.minValue, this.maxValue)
    }

    public isWithin(value: number): boolean
    {
        return this.minValue <= value && value <= this.maxValue
    }

    public at(ratio: number): number
    {
        return lerp(this.minValue, this.maxValue, ratio);
    }

    public clamp(value: number): number
    {
        return clamp(value, this.minValue, this.maxValue);
    }

    public expand(expansion: number): RangedNumber
    {
        return this.offset(-expansion, expansion);
    }

    public offset(min: number, max?: number): RangedNumber
    {
        max ??= min

        var newMin = this.minValue - min;
        var newMax = this.maxValue - max;

        return new RangedNumber(Math.min(newMin, newMax), Math.max(newMin, newMax));
    }
    
    public contains(value: number): boolean
    {
        return value >= this.minValue && value <= this.maxValue;
    }

    public gapMod(value: number): number
    {
        return this.minValue + (value % this.gap);
    }
    public gapModBounce(value: number): number
    {
        value %= this.gap * 2

        if (value <= this.gap)
        {
            return this.minValue + value
        }
        else
        {
            return this.maxValue + this.gap - value
        }
    }

    public toString(): string
    {
        return `RangedNumber(${softToFixed(this.minValue)}<->${softToFixed(this.maxValue)})`;
    }
}

export function navigatorSupportsClipboard(): boolean
{
    return navigator.clipboard != null && typeof navigator.clipboard.readText === "function" && typeof navigator.clipboard.writeText === "function"
}

export function clearObj(obj: {[key: ObjKey]: any})
{
    for(const key in obj)
    {
        delete obj[key]
    }
}