<script lang="ts">
    import type { Snippet } from "svelte";
    import { Style } from "../data/styles";

    let
    {
        title,
        header,
        children,
        footer,
        onClose,
        closable = true,
        style = Style.DEFAULT,
    }:
    {
        title?: string
        header?: Snippet
        children: Snippet
        footer?: Snippet
        onClose?: () => void
        closable?: boolean
        style?: Style
    } = $props()

    function onUserClose()
    {
        if(!closable)
        {
            return
        }

        if (onClose)
        {
            onClose()
        }
    }

    function handleKeyUp(e: KeyboardEvent)
    {
        switch(e.key.toLowerCase())
        {
            case "escape":
            {
                onUserClose()
            }
            break
        }
    }
</script>

<div
    class="backdrop"
    onkeyup={handleKeyUp}
    role="menu"
    tabindex="-1"
>
    <div class="window"
        style:background-color={style.get("background")}
    >
        <div class="title">
            {title}
        </div>
        {#if closable}
        <button
            class="close_button"
            type="button"
            onclick={onUserClose}
            aria-label="Close"
        >
            ✕
        </button>
        {/if}

        <div>
            {@render header?.()}
    
            {@render children()}
    
            {@render footer?.()}
        </div>
    </div>
</div>

<style>
