<script lang="ts">
    import type { Snippet } from "svelte";
    import type { SvelteCircle } from "../comps_data/circles.svelte";
    import type { Pos } from "../util/interfaces";

    let
    {
        circle,
        pos,
        diameter,
        color,
        children,
    }:
    {
        circle: SvelteCircle,
        pos?: Pos,
        diameter?: number,
        color?: string,
        children?: Snippet,
    } = $props()
</script>

<style>
    .circle
    {
        position: absolute;
        border-radius: 50%;
        border: 2px solid red;
        background: transparent;
        pointer-events: none;
    }
</style>

<div class="circle"
    bind:this={circle.el}
    style:left={(pos?.x ?? 0) - (diameter ?? circle.size) / 2 + "px"}
    style:top={(pos?.y ?? 0) - (diameter ?? circle.size) / 2 + "px"}
    style:width={diameter ?? circle.size + "px"}
    style:height={diameter ?? circle.size + "px"}
    style:border-color={color ?? circle.color}
    style:display={circle.visible ? "block" : "none"}
>
    {@render children?.()}
</div>