<script lang="ts" generics="TABS extends Record<string, Snippet>">
import { untrack, type Snippet } from "svelte";
import PanelComp from "./PanelComp.svelte";
import ButtonsPanelComp from "./ButtonsPanelComp.svelte";
import type { TitleAction } from "../../comps_data/app.svelte";

let
{        
    tabs,
    selectedTabName = "",
    onInternalTabChange,
    flexDirection = "row",
}:
{        
    tabs: TABS,
    selectedTabName?: keyof TABS
    onInternalTabChange?: (name: keyof TABS) => void
    flexDirection?: "column" | "row"
} = $props()

const buttons: TitleAction[] = $state([])

$effect(() =>
{
    tabs

    untrack(() =>
    {
        buttons.length = 0
    
        for(const title of Object.keys(tabs))
        {
            buttons.push
            ({
                title,
                action: () =>
                {
                    if(selectedTabName == title) return
                    selectedTabName = title
                    if (onInternalTabChange) onInternalTabChange(title)
                }
            })
        }
    })
})

function isSelected(name: keyof TABS)
{
    return name === selectedTabName
}
</script>

<PanelComp
    >
    {#snippet header()}
        <div class="tab_bar">
            <ButtonsPanelComp
                items={buttons}
                flexDirection={flexDirection}
                selected={data => isSelected(data.title)}
                />
        </div>
    {/snippet}

    {#if Object.keys(tabs).length > 0}
    <section>
        {@render tabs[selectedTabName]?.()}
    </section>
    {/if}
</PanelComp>

<style>
.tab_bar
{
    flex: 0;
    display: flex;
    overflow-x: auto;
    flex-shrink: 0;
    gap: 4px;
    padding: 4px;
    margin-bottom: 4px;
    border-bottom: 1px solid rgba(255,255,255,0.25);
    justify-content: center;
}

section
{
    flex: 1;
    overflow-x: hidden;
    overflow-y: auto;
    min-height: 0;
    position: relative;
}
</style>