export type TitleObj = { title: string }
export type TitleAction = TitleObj & { action: (data: TitleAction) => void}
export type TitleTitleActions = TitleObj & {actions: TitleAction[]}
export type ContextMenuItem = TitleObj | TitleAction | TitleTitleActions

export type ItemTitleAction<T> = TitleObj & {item: T, action: (data: ItemTitleAction<T>) => void}

export async function waitTick(tickCount: number = 1, then: () => void = noopTrue)
{
    for(let i = 0; i < tickCount; i++)
    {
        await tick()
    }
    then()
}

export async function waitHack(then: () => void = noopTrue)
{
    await waitMs(HACK_WAIT_MS)
    then()
}

