export let contextMenuState = writable<ContextMenuState>(EMPTY_CONTEXT_MENU)

export const pointerLast: Pos = Pos.zero()
export const touchPos: Pos = Pos.zero()
export const touchWorldPos: Pos = Pos.zero()

export function updateTouchPos(touches: TouchList)
{
    touchPos.x = 0
    touchPos.y = 0

    for(const touch of touches)
    {
        touchPos.x += touch.clientX
        touchPos.y += touch.clientY
    }

    touchPos.x /= touches.length
    touchPos.y /= touches.length

    touchWorldPos.x = touchPos.x
    touchWorldPos.y = touchPos.y

    translatePosToWorldPos(touchWorldPos)
}

export function updatePointerLast(x: number, y: number)
{
    pointerLast.x = x
    pointerLast.y = y
}

export function updatePointerLastTouch()
{
    pointerLast.x = touchPos.x
    pointerLast.y = touchPos.y
}