<script lang="ts">
    import { Tab } from "../comps_data/tabs.svelte";
    import ButtonComp from "./ButtonComp.svelte";

let
{
    tab,
}:
{
    tab: Tab
} = $props()

function onMouseDown(e: MouseEvent)
{
    switch(e.button)
    {
        case 2:
        {
            tab.openContextMenu(e.clientX, e.clientY)
        }
        break
    }
}
</script>

<div
    bind:this={tab.el}
    on:mousedown={onMouseDown}
    >
    <ButtonComp
        onClick={(e) => tab.onClick()}
        title={tab.name}
        index={tab.getDynamicIndex()}
        selected={tab.selected}
        width="100%"
        />
</div>