<script lang="ts">
    import { playPopSound } from "../data/audio";
    import { Style } from "../data/styles";
    import { noopTrue } from "../util/util.svelte";

    let
    {
        size = "1.6em",
        el = $bindable(),

        value = false,
        onToggle = noopTrue,

        index = 0,
        style = Style.DEFAULT,

        backgroundHueOffset = 0,
        backgroundSaturationOffset = 0,
        backgroundLightnessOffset = 0,

        checkmarkHueOffset = 0,
        checkmarkSaturationOffset = 0,
        checkmarkLightnessOffset = 0,
    } :
    {
        size?: string,
        el?: HTMLButtonElement,

        value?: boolean,
        onToggle?: (newState: boolean) => void,

        index?: number,
        style?: Style,

        backgroundHueOffset?: number,
        backgroundSaturationOffset?: number,
        backgroundLightnessOffset?: number,

        checkmarkHueOffset?: number,
        checkmarkSaturationOffset?: number,
        checkmarkLightnessOffset?: number
    } = $props()
</script>

<button
    bind:this={el}
    class="checkbox"
    style:width={size}
    style:height={size}
    style:background={style.getDynamicColor(index + 1, backgroundHueOffset, backgroundSaturationOffset, backgroundLightnessOffset)}
    style:color={style.getDynamicColor(index - 1, checkmarkHueOffset, checkmarkSaturationOffset, checkmarkLightnessOffset)}
    onclick={() => { onToggle(!value); playPopSound() }}
    title={value ? "Checked" : "Unchecked"}
>
    <div class="checkmark"
        style:font-size={size}
    >
        {value ? "✔" : " "}
    </div>
</button>
<style>
.checkbox
{
    display: flex;
    align-items: center;
    justify-content: center;

    cursor: pointer;
    user-select: none;
}
</style>