    public getAliveChildren(): Node[]
    {
        return this.children.filter(child => child.alive)
    }

    public getChildrenRecursive(filter: (node: Node) => boolean = noopTrue): Node[]
    {
        const nodes: Node[] = []

        this.forEachChildRecursive(node =>
        {
            if(filter(node))
            {
                nodes.push(node)
            }
        })

        return nodes
    }

    public getAliveChildrenRecursive(): Node[]
    {
        return this.getChildrenRecursive(node => node.alive)
    }

    public forEachParent(callback: (parent: Node) => unknown | boolean)
    {
        let parent = this.parent

        while(parent != null)
        {
            const action = callback(parent)

            if(action != null)
            {
                if(action === true)
                {
                    break
                }
            }

            parent = parent.parent
        }
    }

