    public delete(doHistory: boolean = true, addToHistory: boolean = true): DeleteNodeAction | undefined
    {
        if(this.isRoot)
        {
            return
        }

        if(!this.alive)
        {
            return
        }

        this.data.unregisterNode(this)
        deletedNodesHistory.push(this)

        playPopSound()
        this.tab.deselectNodes(this.getThisAndAllChildrenRecursiveSet())

        let action: DeleteNodeAction | undefined = undefined

        if(doHistory)
        {
            const childrenToResurrect: Node[] = this.getAliveChildren()

            action = new DeleteNodeAction(this.parent, this, this.childIndex, childrenToResurrect, this.mimicOf)

            if(addToHistory)
            {
                addActionToHistory(action)
            }
        }

        // if(this.mimicOf != null)
        // {
        //     this.mimicOf.mimickedBy.delete(this.mimicMaster)
        // }

        this.alive = false

        const finish = () =>
        {
            const tab = this.tab

            // In case of async delete and undo
            if(!this.alive)
            {
                this.detachFromParent()
            }

            tab.update()
        }

        if(this.shouldAnimate())
        {
            const deathTimer = new Timer()
            const deathDurationMs = userConfig.get("NODE_DEATH_ANIMATION_TIME_MS")

            this.forThisAndEachChildRecursive(node =>
            {
                // node.setPosition((node.left + 100) * 2, node.top * 2, true)
                node.setPosition(0, 0)
                node.alive = false
            })

            this.forThisAndEachChildRecursive(node => node.animateOpacity(1, 0, deathDurationMs))

            unfocusTabIndex()
            this.updateTreeRecursive()

            setTimeout(() =>
            {
                finish()
            }, deathDurationMs)
            
            return action
        }
    
        finish()

        return action
    }

