    get childIndexIgnoringNotAliveAndSkipped(): number
    {
        if(this.parent == null)
        {
            return -1
        }

        let index = 0

        for(const child of this.parent.children)
        {
            if(child === this)
            {
                return index
            }

            if(child.alive)
            {
                index++
            }
        }

        return index
    }

    getDynamicIndex(): number
    {
        if(this.tab == null)
        {
            log(`Node ${this.id} has no tab, returning -1 for dynamic index!`, false)

            return -1
        }

        const tabIndex = this.isRoot ? this.tab.getDynamicIndex() : 0
        const parentIndex = (this.lineToParentNode?.getDynamicIndex() ?? this.parent?.getDynamicIndex() ?? this.depth)
        const childIndex = 1 + Math.max(0, this.childIndexIgnoringNotAliveAndSkipped)

        const dynamicIndex = tabIndex + parentIndex + childIndex

        if(this.id == 19)
        {
            if(dynamicIndex == 4)
            {
                this
            }
        }

        return dynamicIndex
    }

