    public move(amount: number)
    {
        if(this.parent == null)
        {
            return
        }

        if(this.parent.children.length <= 1)
        {
            return
        }

        const index = this.childIndex
        let newIndex = index - amount

        if(newIndex < 0)
        {
            newIndex = this.parent.children.length - 1
        }
        else if(newIndex >= this.parent.children.length)
        {
            newIndex = 0
        }

        this.parent.swapChildrenIndex(index, newIndex)
        this.parent.updateChildrenRecursive()

        console.log
    }

