    public getSiblingNode(offset: number, allowThis: boolean): Node
    {
        if(this.isRoot)
        {
            return null!
        }

        const siblings = this.parent.getAliveChildren()

        offset = Math.floor(offset)

        const sibling = getWrapped(siblings, this.childIndex, offset)

        if(sibling == this)
        {
            return allowThis ? this : null!
        }

        return sibling
    }

