    public updateChildrenSizeCache(): number
    {
        this.widestChild = 0
        this.childrenHeight = 0
        this.widestChildRecursive = 0

        if(this.childrenVisible)
        {
            for(let i = 0; i < this.children.length; i++)
            {
                const child = this.children[i]
    
                if(!child.alive)
                {
                    continue
                }
                
                if(i > 0)
                {
                    this.childrenHeight += projectConfig.get("NODE_VERTICAL_SPACING")
                }
    
                this.childrenHeight += child.totalHeight
                
                this.widestChild = Math.max(this.widestChild, child.size.x)
                this.widestChildRecursive = Math.max(this.widestChildRecursive, child.totalWidth)
            }
        }
        
        this.totalHeight = Math.max(this.size.y, this.childrenHeight)
        
        this.totalWidth = this.size.x

        if(this.widestChildRecursive > 0)
        {
            this.totalWidth += projectConfig.get("NODE_HORIZONTAL_SPACING")
            this.totalWidth += this.widestChildRecursive
        }

        return this.childrenHeight
    }

    async updateTreeRecursive(nextTick: boolean = false, animate: boolean = this.shouldAnimate(), tab: Tab = this.tab)
    {
        if(nextTick)
        {
            await tick()
            this.updateTreeRecursive(false, animate, tab)
            return
        }

        if(tab == null)
        {
            messages.addErrorMessage(`Node ${this.id} has no tab, can't update tree recursively!`)
            return
        }

        tab.update(false, animate)
    }

    updateChildrenRecursive(animate: boolean = this.shouldAnimate())
    {
        for(const child of this.children)
        {
            child.updateChildrenRecursive(animate)
        }

        this.updateChildren(animate)
    }

    public getChildVerticallyClosestToParent(): Node
    {
        let closestChild: Node = null!
        let closestDistance = Number.POSITIVE_INFINITY

        for(const child of this.children)
        {
            const distance = Math.abs(child.midY)

            if(distance < closestDistance)
            {
                closestDistance = distance
                closestChild = child
            }
        }

        return closestChild
    }

