    tryStealIdentityfromText(): boolean
    {
        let text = this.textEl.value.trim()

        if(text.startsWith("{") && text.endsWith("}"))
        {
            if(!this.isProductOfIdentityTheft())
            {
                const identityTheftTargetId = text.substring(1, text.length - 1)

                const success = this.setIdentityTheftTargetFromNodeName(identityTheftTargetId)

                if(success)
                {
                    this.data.setText(this.textEl.value, false, false)
                    this.data.setFormattedText(wrapIdentityTheftWithFunny(this.identityTheftTarget.data.formattedText))
                    return true
                }
            }
        }
        else
        {
            this.setIdentityTheftNode(null)
        }
        
        return false
    }

