    public stopEditing(save: boolean)
    {
        setTyping(false)
        
        if(!this.alive)
        {
            return
        }

        const startHeight = this.size.y

        this.stoppedEditingOnMs = Date.now()
        this.editing = false

        if(save)
        {
            if(this.data.text != this.textEl.value)
            {
                //#region identity theft
                const identityStolen = this.tryStealIdentityfromText()
    
                // log(`Node ${this.id} | identity stolen: ${identityStolen}`)
                
                if(!identityStolen)
                {
                    this.tryStealIdentityfromText()
                }
    
                if(identityStolen)
                {
                    this.data.forEachNodeExcept(this, node => node.setText(this.textEl.value))
                }
                else
                {
                    this.data.forEachNode(node => node.setText(this.textEl.value))
                }
                //#endregion identity theft
            
                
            }

            //Doesn't work
            if(this.isRoot)
            {
                this.tab.name = this.textEl.value
                Tab.update(true)
            }
        }

        this.focus()

        this.updateSize()

        const endHeight = this.size.y
        const heightDiff = endHeight - startHeight

        if(heightDiff !== 0)
        {
            this.offsetPosition(0, -heightDiff / 2, false)
        }

        this.updateTreeRecursive(false, false)
    }

