    setIdentityTheftTargetFromNodeName(nodeName: string): boolean
    {
        const parsedNumber = parseFloat(nodeName)
        const node = getNodeById(parsedNumber)

        if(node != null)
        {
            return this.setIdentityTheftNode(node)
        }

        const matches = getNodes(node => node.data.text === nodeName)

        if(matches.length == 0)
        {
            return this.setIdentityTheftNode(null)
        }

        if(matches.length > 1)
        {
            log(`Found multiple nodes with name "${nodeName}", using the first one as reference node for node ${this.id}`)
        }

        return this.setIdentityTheftNode(matches[0])
    }

    setIdentityTheftTargetFromNodeId(nodeId: number)
    {
        if(isNaN(nodeId))
        {
            return
        }

        const matches = getNodes(node => node.id === nodeId)

        if(matches.length == 0)
        {
            log(`No nodes data found with id "${nodeId}" to set as reference node for node ${this.id}`)
            this.setIdentityTheftNode(null)
            return
        }

        this.setIdentityTheftNode(matches[0])

        if(matches.length > 1)
        {
            log(`Found multiple nodes with id "${nodeId}", using the first one as reference node for node ${this.id}`)
        }
    }

    setIdentityTheftNode(node: Node | null): boolean
    {
        if(node == this.identityTheftTarget)
        {
            return false
        }

        const targetNotNull = node != null

        if(targetNotNull)
        {
            if(this.hasParent(node))
            {
                messages.addErrorMessage(getInfiniteRecursionScareText(), undefined, 10)
                return false
            }
        }

        if(this.identityTheftTarget != null)
        {
            this.identityTheftTarget.identityTheftBy.delete(this)
            this.forEachChildRecursive(child => child.data.unregisterNode(child))
        }

        this.identityTheftTarget = node!

        if(targetNotNull)
        {
            node.identityTheftBy.add(this)
            this.children = []
            stealIdentity(this.tab, this, this.identityTheftTarget.children)

            // log(`[${this.children.length}] Node ${this.id} is now stealing identity from node ${node.id}`)
        }
        else
        {
            this.children = this.trueChildren
            // log(`[${this.children.length}] Node ${this.id} is no longer stealing identity from any node`)
        }

        this.updateTreeRecursive(true)

        return node != null
    }

    isProductOfIdentityTheft(): boolean
    {
        if(this.mimickedBy.size > 0)
        {
            return true
        }

        return false
    }

    toText(toTextOrString: boolean = true, suffixDecider?: (node: Node) => string, layer: number = 0): string
    {
        const padding = "    ".repeat(layer + 1)

        let text = toTextOrString ? this.data.text : this.toString().replaceAll("\n", `\n${padding}`)

        if(suffixDecider != null)
        {
            text += `: ${suffixDecider(this)}`
        }

        for(const child of this.children)
        {
            text += `\n${padding}${child.toText(toTextOrString, suffixDecider, layer + 1)}`

            if(suffixDecider != null)
            {
                text += `: ${suffixDecider(child)}`
            }
        }

        return text
    }

    forEachMimickedByAndIdentityThief(callback: (mimic: Node) => void)
    {
        for(const identityThief of this.identityTheftBy)
        {
            callback(identityThief)
        }

        for(const [mimicMaster, mimic] of this.mimickedBy)
        {
            callback(mimic)
        }
    }

