    isTopInHierarchy(nodes: Node | Set<Node>): boolean
    {
        return !this.isChildInHierarchy(nodes)
    }

    isChildInHierarchy(nodes: Node | Set<Node>): boolean
    {
        let isChild = false

        if(nodes instanceof Node)
        {
            if(nodes != this)
            {
                this.forEachParent(parent =>
                {
                    if(parent == nodes)
                    {
                        isChild = true
                        return ForAction.Break
                    }
                })
            }
        }
        else
        {
            for(const node of nodes)
            {
                if(this.isChildInHierarchy(node))
                {
                    isChild = true
                    break
                }
            }
        }

        return isChild
    }

