export function getClosestNodeToPosition(pos: Pos, goalRectPoint: Direction2D9 = Direction2D9.Center, distanceLimit: number = Number.POSITIVE_INFINITY, filter: (node: Node) => boolean = noopTrue): [Node, number]
{
    let closestNode: Node = null!
    let closestDistance = Number.POSITIVE_INFINITY

    const pointName = Direction2D9[goalRectPoint]

    for(const node of nodesMap.values())
    {
        if(node.el == null)
        {
            continue
        }

        if(!node.alive)
        {
            continue
        }

        if(!filter(node))
        {
            continue
        }

        const nodeBB = node.getWorldRect()
        const goalPos: Pos = getRectPoint(nodeBB, goalRectPoint)

        if(VISUALIZE_NODE_DRAG)
        {
            setDebugCircle(`${node.id}_${pointName}`, goalPos, node.getBackgroundColor())
        }

        const distanceSq = ((goalPos.x - pos.x) ** 2) + ((goalPos.y - pos.y) ** 2)

        if(distanceSq < closestDistance)
        {
            if(VISUALIZE_NODE_DRAG)
            {
                setDebugCircle(`closest`, goalPos, "yellow")
            }
            closestDistance = distanceSq
            closestNode = node
        }
    }

    
    if(distanceLimit <= 0 || closestDistance <= distanceLimit ** 2)
    {
        return [closestNode, closestDistance]
    }

    return [null!, Number.POSITIVE_INFINITY]
}

export function multiDeleteNodes(nodes: Iterable<Node>, addToHistory: boolean)
{
    const tasks: DeleteNodeAction[] = []

    for(const node of nodes)
    {
        if(node.isRoot)
        {
            continue
        }

        if(!node.alive)
        {
            continue
        }

        const children = node.getAliveChildrenRecursive()

        tasks.push(new DeleteNodeAction(node.parent, node, node.childIndex, children))

        node.delete(false)
    }

    if(addToHistory)
    {
        addActionToHistory(tasks)
    }

    return tasks
}

export function shouldSelectParentNodeOnElClick(clickedEl: HTMLElement)
{
    for(const elClass of clickedEl.classList)
    {
        const lowercaseClass = elClass.toLowerCase()

        if(lowercaseClass.includes("checkbox"))
        {
            return false
        }
        else if(lowercaseClass.includes("toggle"))
        {
            return false
        }
    }

    return true
}

export function nodesSetToArray(nodesSet: Set<Node>): Node[]
{
    const nodes = [...nodesSet]

    nodes.sort((a, b) => a.childIndex - b.childIndex)

    return nodes
}

export function isWithinDraggingDistanceSq(distanceSq: number)
{
    if(100 ** 2 < distanceSq)
    {
        return true
    }

    return false
}

export function setChildrenVisible(nodes: Node[], childrenVisible: boolean)
{
    const actions: EditNodePropertyAction<"childrenVisible">[] = []

    for(const node of nodes)
    {
        if(node.getAliveChildrenCount() > 0)
        {
            if(node.childrenVisible != childrenVisible)
            {
                const action = node.setChildrenVisible(childrenVisible, false)

                if(action != null)
                {
                    actions.push(action)
                }
            }
        }
    }

    addActionToHistory(actions)
}

export function setCompletion(nodes: Node[], completion: number)
{
    const actions: EditNodeDataPropertyAction<"completion">[] = []

    for(const node of nodes)
    {
        const newActions = node.setCompletionRecursive(completion, false)

        if(newActions != null)
        {
            addAllFromTo(newActions, actions)
        }
    }

    addActionToHistory(actions)
}

export function getNextAvailableTagName(nodes: (Node | NodeData)[], baseTagName: string = "New Tag"): string
{
    let i = 0
    let tagName: string
    let exists: boolean

    do
    {
        exists = false
        tagName = `${baseTagName}${i > 0 ? ` ${i}` : ""}`
        forEachArray(nodes, node =>
        {
            node = getNodeData(node)

            if(node.hasTag(tagName))
            {
                exists = true
                return true
            }
        })
        ++i
    }
    while(exists)

    return tagName
}

export function createTag(nodes: (Node | NodeData)[], baseTagName: string = "New Tag")
{
    const individualTags: Tag[] = []

    const actions: AddNodeTagAction[] = []
    
    const tagName = getNextAvailableTagName(nodes, baseTagName)

    forEachArray(nodes, node =>
    {
        node = getNodeData(node)

        const tag = node.setTag(tagName, "")
        individualTags.push(tag)

        actions.push(new AddNodeTagAction(node, tag))
    })

    addActionToHistory(actions)

    return individualTags
}

export function deleteTags(nodes: (Node | NodeData)[])
{
    const actions: AddNodeTagAction[] = []

    forEachArray(nodes, node =>
    {
        node = getNodeData(node)

        forEach([...node.tagsComps], tag =>
        {
            actions.push(node.deleteTag(tag.name, false))
        })
    })

    addActionToHistory(actions)
}

function stealIdentity(tab: Tab, parentMimic: Node, nodes: Node[])
{
    for(const node of [...nodes])
    {
        const clone = new Node(tab, node.data, parentMimic, EMPTY_ARRAY)

        clone.mimicOf = node
        clone.mimicMaster = parentMimic.mimicMaster ?? parentMimic
        node.mimickedBy.set(clone.mimicMaster, clone)

        if(node.children.length > 0)
        {
            stealIdentity(tab, clone, node.children)
        }
    }
}

export function getAllRelatedNodes(nodes: Iterable<Node>): Set<Node>
{
    const relatedNodes: Set<Node> = new Set()

    for(const node of nodes)
    {
        addAllFromTo(node.data.nodesDisplayingThisData, relatedNodes)
    }

    return relatedNodes
}

export function forEachTab(nodes: Iterable<Node>, callback: (tab: Tab) => unknown | boolean, filter: (tab: Tab) => boolean = noopTrue)
{
    const tabs: Set<Tab> = new Set()

    for(const node of nodes)
    {
        tabs.add(node.tab)
    }

    forEach(tabs, tab =>
    {
        return callback(tab)
    }, filter)
}

export function updateTrees(nodes: Iterable<Node>, nextTick: boolean = false)
{
    forEachTab(nodes, tab =>
    {
        tab.update(nextTick)
    })
}

export function filterOutChildrenNodes(nodes: Set<Node>)
{
    const topNodes: Set<Node> = new Set()

    forEach
    (
        nodes,
        node => topNodes.add(node),
        node => node.isTopInHierarchy(nodes),
    )

    return topNodes
}