<script lang="ts">
    import { Style } from "../../data/styles";
    import ButtonsPanelComp from "../panels/ButtonsPanelComp.svelte";
    import { contextMenuState, EMPTY_CONTEXT_MENU, noModifiersHeld, type NodeContextMenuType, type TitleAction } from "../../comps_data/app.svelte";
    import { untrack } from "svelte";
    import { createTag, deleteTags, filterOutChildrenNodes, multiDeleteNodes, setChildrenVisible, setCompletion } from "../../comps_data/nodes.svelte";
    import { addActionToHistory, type DeleteNodeAction } from "../../util/undoredo.svelte";
    import { addAllFromTo } from "../../util/util.svelte";

let
{
    style = Style.DEFAULT,
    data: data,
}:
{
    style?: Style
    data: NodeContextMenuType
} = $props()

function getTab()
{
    return data.targets[0].tab
}

const actions: TitleAction[] = $state([])

$effect(() =>
{
    untrack(() =>
    {
        actions.length = 0

        const tab = getTab()
        
        if(tab == null)
        {
            return
        }

        let canDeleteTab = false
        let canDelete = data.targets.length != 1 || !data.targets[0].isRoot
        let hasChildren = false
        let hasHiddenChildren = false
        let hasVisibleChildren = false
        let hasCompleted = false
        let hasNotCompleted = false
        let hasTags = false
        const canCopy = data.targets.length > 0
        const canPaste = canCopy

        for(const node of data.targets)
        {
            if(node.isRoot) canDeleteTab = true

            const aliveChildren = node.getAliveChildren()

            if(aliveChildren.length > 0)
            {
                hasChildren = true

                if(node.childrenVisible)
                {
                    hasVisibleChildren = true
                }
                else
                {
                    hasHiddenChildren = true
                }
            }

            if(node.data.isCompleted())
            {
                hasCompleted = true
            }
            else
            {
                hasNotCompleted = true
            }

            if(node.data.tagsComps.length > 0)
            {
                hasTags = true
            }
        }

        if(canDelete)
        {
            actions.push({ title: "Delete", action: () => getTab().deleteSelectedNodes() })
        }

        if(hasChildren)
        {
            actions.push({ title: "Delete Child Nodes", action: () =>
            {
                const parents = filterOutChildrenNodes(tab.selectedNodes)

                const actions: DeleteNodeAction[] = []

                for(const parent of parents)
                {
                    addAllFromTo(multiDeleteNodes(parent.children, false), actions)
                }

                addActionToHistory(actions)
            }})

            if(hasVisibleChildren)
            {
                actions.push({ title: "Hide Nodes", action: () => setChildrenVisible(data.targets, false) })
            }
    
            if(hasHiddenChildren)
            {
                actions.push({ title: "Reveal Nodes", action: () => setChildrenVisible(data.targets, true) })
            }
        }

        if(hasNotCompleted)
        {
            actions.push({ title: "Complete", action: () => setCompletion(data.targets, 1) })
        }

        if(hasCompleted)
        {
            actions.push({ title: "Uncomplete", action: () => setCompletion(data.targets, 0) })
        }

        if(canCopy)
        {
            actions.push({ title: "Copy", action: () => tab.copySelectedNodesToClipboard(false, true) })
            actions.push({ title: "Cut", action: () => tab.copySelectedNodesToClipboard(true, true) })
        }

        if(canPaste)
        {
            actions.push({ title: "Paste", action: () => tab.pasteFromClipboard() })
        }

        actions.push({ title: "Create Tag", action: () => createTag(data.targets) })

        if(hasTags)
        {
            actions.push({ title: "Delete Tags", action: () => deleteTags(data.targets) })
        }
    })
})
</script>

<div class="title">{data.targets.length == 1 ? data.targets[0].data.text : `${data.targets.length} Nodes`}</div>
<ButtonsPanelComp
    style={style}
    afterItemClicked={(data) =>
    {
        if(noModifiersHeld() || data.title.includes("Delete"))
        {
            contextMenuState.set(EMPTY_CONTEXT_MENU)
        }
    }}
    items={actions}
/>