import { softToFixed, toStamp } from "../util.svelte"

export class Timer
{
    private _startMs: number = 0
    private _lastIncrementMs: number = 0
    private _count = 0

    public constructor()
    {
        this.reset()
    }

    public reset()
    {
        this._startMs = Date.now()
        this._lastIncrementMs = this._startMs
        this._count = 0
    }

    get startMs(): number
    {
        return this._startMs
    }

    get elapsedMs(): number
    {
        return Date.now() - this._startMs
    }

    get elapsedS(): number
    {
        return this.elapsedMs / 1000
    }

    public increment(incrementBy: number = 1, updateLoadingBar: boolean = false): number
    {
        this._count += incrementBy
        this._lastIncrementMs = Date.now()

        return this._count
    }

    get lastIncrementMs(): number
    {
        return this._lastIncrementMs
    }

    get lastIncrementGapMs(): number
    {
        return Date.now() - this._lastIncrementMs
    }

    get lastIncrementGapS(): number
    {
        return this.lastIncrementGapMs / 1000
    }

    get count(): number
    {
        return this._count
    }


    get countPerSecond(): number
    {
        return this._count / this.elapsedS
    }

    get countPerSecondString(): string
    {
        return `${softToFixed(this.countPerSecond)}/s`
    }

    public isFinished(goalCount: number): boolean
    {
        return goalCount <= this._count
    }

    public getETASecondsForCount(goalCount: number): number
    {
        return (goalCount - this._count) / this.countPerSecond
    }

    public getETASecondsForCountString(goalCount: number): string
    {
        return toStamp(this.getETASecondsForCount(goalCount))
    }

    public getCountAndPercentString(goalCount: number, clampCountToGoal: boolean = false): string
    {
        const count = clampCountToGoal ? Math.min(this._count, goalCount) : this._count

        if(count == 0)
        {
            return `[0/${goalCount.toFixed(2)}]~[0.00%]`
        }

        const percent = (count / goalCount) * 100
        const countString = Number.isInteger(count) ? count.toFixed(0) : count.toFixed(2)
        
        return `[${countString}/${softToFixed(goalCount)}]~[${(percent).toFixed(2)}%]`
    }

    public getFullStatsString(goalCount: number, clampCountToGoal: boolean = false): string
    {
        if(this._count == 0)
        {
            return this.getCountAndPercentString(goalCount, clampCountToGoal)
        }

        return `${this.getCountAndPercentString(goalCount, clampCountToGoal)} | ${this.getETASecondsForCountString(goalCount)} | ${this.countPerSecondString}`
    }

    public getMsRatioSinceStartToDurationMs(durationMs: number): number
    {
        return this.elapsedMs / durationMs
    }

    public getMsRatioSinceStartToEndMs(endMs: number): number
    {
        return this.elapsedMs / (endMs - this.startMs)
    }
}