<script lang="ts">
    import { waitTick } from "../comps_data/app.svelte";
    import { Tab } from "../comps_data/tabs.svelte";
    import { tabs } from "../comps_data/tabs.svelte";
    import ItemsPanelComp from "./panels/ItemsPanelComp.svelte";
    import TabComp from "./TabComp.svelte";
</script>

<ItemsPanelComp
    items={$tabs}
    createNew={() =>
    {
        const tab = Tab.fromNodeJson()

        tab.onClick()
        
        waitTick(1, () =>
        {
            waitTick(1, () =>
            {
                tab.rootNode.startEditing()
            })
        })

        return tab
    }}

    onHamburger={(tab, i) =>
    {
        tab.openContextMenu()
    }}
>
    {#snippet itemSnippet(tab)}
        <TabComp tab={tab}>
        </TabComp>
    {/snippet}
</ItemsPanelComp>