<script lang="ts">
    import { dev, waitTick } from "../comps_data/app.svelte";
    import { Style } from "../data/styles";
    import { isString, NEW_LINE_REGEX, noopTrue } from "../util/util.svelte";


let
{
    value = "",
    labelValue = value,

    textEl = $bindable(),
    labelEl = $bindable(),

    onInput = noopTrue,
    correcter = (text) => text,
    correctOnEveryInput = false,
    onBlur = noopTrue,
    onElementsBound = noopTrue,

    editing = false,
    startEditingOnDoubleClick = true,
    stopEditingOnBlur = true,
    enterCloses = true,
    
    style = Style.DEFAULT,
    index = 0,

    labelCursor = startEditingOnDoubleClick ? "pointer" : "auto",
} : 
{
    value?: string,
    labelValue?: string,

    textEl?: HTMLTextAreaElement,
    labelEl?: HTMLDivElement,

    onInput?: (e: Event, target: HTMLTextAreaElement) => void
    correcter?: (text: string) => string
    correctOnEveryInput?: boolean
    onBlur?: (e: FocusEvent, text: string) => unknown | string
    onElementsBound?: (textEl: HTMLTextAreaElement, labelEl: HTMLDivElement) => void

    editing?: boolean
    startEditingOnDoubleClick?: boolean
    stopEditingOnBlur?: boolean
    enterCloses?: boolean

    style?: Style
    index?: number

    labelCursor?: "auto" | "pointer" | "text"
} = $props()

$effect(() =>
{
    if(editing)
    {
        if(textEl != null)
        {
            const lines = value.split(NEW_LINE_REGEX)
            textEl.rows = lines.length
            textEl.cols = Math.max(...lines.map(line => line.length), ...[1]) + 1
        }
    }
})

function bindTextEl(el: HTMLTextAreaElement)
{
    textEl = el
}

function bindLabelEl(el: HTMLDivElement)
{
    labelEl = el
    onElementsBound(textEl!, labelEl)
}

function correctText()
{
    value = textEl!.value = correcter(textEl!.value)
}
</script>

<div>
    <!-- text -->
    {#if dev}
    <!-- e: {editing} -->
    {/if}
    <textarea class="text"
        use:bindTextEl

        onkeydown={e =>
        {
            if(enterCloses)
            {
                if(e.key.toLowerCase() == "enter")
                {
                    textEl!.blur()
                }
            }
        }}
        
        oninput={(e) => 
        {
            if(correctOnEveryInput)
            {
                correctText()
            }

            onInput(e, e.currentTarget)
        }}
        style:display={editing ? 'block' : 'none'}
        
        onblur={(e) =>
        {
            correctText()
            const newText = onBlur(e, value)
            if(isString(newText))
            {
                textEl!.value = value = newText
            }

            if(stopEditingOnBlur)
            {

                editing = false
            }
        }}

        style:color={style.get("textColor")}

        value={value}
    ></textarea>

    <div class="text label"
        use:bindLabelEl
        style:innerHtml={value}
        
        style:color={style.get("textColor")}

        style:display={editing ? 'none' : 'block'}

        style:cursor={labelCursor}

        role="presentation"
        ondblclick={e =>
        {
            if(startEditingOnDoubleClick)
            {
                editing = true
                waitTick(1, () => textEl!.focus())
            }
        }}
    >
        {#if labelValue.length > 0}
            {@html labelValue}
        {/if}
    </div>
</div>

<style>
.text, .label
{
    font: inherit;

    resize: both;
    border: none;
    white-space: pre;
    align-self: center;

    width: fit-content;
    max-width: 100%;
    min-width: 0;

    opacity: 90%;
}

.label
{
    user-select: none;
    pointer-events: auto;
}
</style>