import type { Pos } from "./interfaces"

export enum Direction2D4
{
    Up,
    Right,
    Down,
    Left,
}

export namespace Direction2D4
{
    export function offsetPosInDirection(pos: Pos, direction: Direction2D4, amount: number): Pos
    {
        switch(direction)
        {
            case Direction2D4.Up:
                return { x: pos.x, y: pos.y - amount }
            case Direction2D4.Right:
                return { x: pos.x + amount, y: pos.y }
            case Direction2D4.Down:
                return { x: pos.x, y: pos.y + amount }
            case Direction2D4.Left:
                return { x: pos.x - amount, y: pos.y }
        }
    }

    export function isVertical(direction: Direction2D4)
    {
        return direction === Direction2D4.Up || direction === Direction2D4.Down
    }

    export function isHorizontal(direction: Direction2D4)
    {
        return direction === Direction2D4.Left || direction === Direction2D4.Right
    }

    export function rightOneLeftMinusOne(direction: Direction2D4)
    {
        switch(direction)
        {
            case Direction2D4.Down:
            case Direction2D4.Right:
                return 1

            case Direction2D4.Up:
            case Direction2D4.Left:
                return -1
        }
    }

    export function getVector(direction: Direction2D4): Pos
    {
        switch(direction)
        {
            case Direction2D4.Up: return { x: 0, y: -1 }
            case Direction2D4.Right: return { x: 1, y: 0 }
            case Direction2D4.Down: return { x: 0, y: 1 }
            case Direction2D4.Left: return { x: -1, y: 0 }
        }
    }

    export function toDirection2D9(direction: Direction2D4): Direction2D9
    {
        switch(direction)
        {
            case Direction2D4.Up: return Direction2D9.Top
            case Direction2D4.Right: return Direction2D9.Right
            case Direction2D4.Down: return Direction2D9.Bottom
            case Direction2D4.Left: return Direction2D9.Left
        }
    }
}

export enum Direction2D9
{
    TopLeft,
    Top,
    TopRight,
    Left,
    Center,
    Right,
    BottomLeft,
    Bottom,
    BottomRight,
}

export namespace Direction2D9
{
    export function toDirection2D4(direction: Direction2D9): Direction2D4
    {
        switch(direction)
        {
            case Direction2D9.Top: return Direction2D4.Up
            case Direction2D9.Right: return Direction2D4.Right
            case Direction2D9.Bottom: return Direction2D4.Down
            case Direction2D9.Left: return Direction2D4.Left

            default: throw new Error(`Cannot convert ${Direction2D9[direction]} to Direction2D4 because it is not a cardinal direction`)
        }
    }
}

