import { get, writable } from "svelte/store";
import { getAllRelatedNodes, multiDeleteNodes, Node } from "./nodes.svelte";
import { StyledComp } from "../util/classes/StyledComp";
import type { IJsonable, NodeJson, TabJson } from "../util/interfaces";
import { Camera } from "./cameras.svelte";
import { tick } from "svelte";
import { userConfig } from "../data/userConfig";
import { CircularArray } from "../util/classes/CircularArray";
import { forEach, forEachNode, getLast, navigatorSupportsClipboard, swapArrayElements, wrapIndex } from "../util/util.svelte";
import { clipboard, contextMenuState, EMPTY_CONTEXT_MENU, jsonNodesClipboard, pointerLast, setClipboard, setClipboardTextOnly, setLeftSidebarOpen, waitHack, waitTick } from "./app.svelte";
import { messages } from "./messages.svelte";
import { playPopSound } from "../data/audio";
import { ForAction } from "../util/enums";
import { NodeData, nodesDataMap } from "./node_data.svelte";
import type { TargetNodesInfo } from "../util/types";
import { addActionToHistory, AddNodeAction, DeleteTabAction, MultiNodedAction, NodedAction } from "../util/undoredo.svelte";

export const tabs = writable<Tab[]>([])
export const currentTab = writable<Tab>(null!)

export function setCurrentTab(tab: Tab)
{
    currentTab.set(tab)
}

export function resetTabs()
{
    tabs.set([])
    setCurrentTab(null!)
}

export class Tab extends StyledComp implements IJsonable
{
    public camera: Camera = $state(null!)
    public name: string
    public readonly nodes: Node[] = []
    public selected = false

    constructor(public rootNode: Node)
    {
        super()

        this.name = this.rootNode?.data.text ?? "New Tab"

        this.camera = new Camera
        (
            this,
            0,
            0,
            1,
        )

        tabs.update(tabs => [...tabs, this])

        Tab.update()
    }

    getFirstSelectedNode(): Node
    {
        for(const node of this.selectedNodes)
        {
            if(!node.alive)
            {
                continue
            }

            return node
        }

        return null!
    }

    setRootNode(rootNode: Node, centerCamera: boolean = true)
    {
        this.rootNode = rootNode
        this.name = rootNode.data.text

        if(centerCamera)
        {
            this.camera.centerToNode(this.rootNode)
        }
    }

    onClick()
    {
        if(!this.selected)
        {
            playPopSound()

            setLeftSidebarOpen(false)

            messages.addMessage(`Selected tab: "${this.name}"`)

            this.select()
        }
    }

    async update(nextTick: boolean = false, animate: boolean = this.shouldAnimate())
    {

        if(nextTick)
        {
            await tick()
            this.update(false)
            return
        }

        if(this.rootNode == null)
        {
            return
        }

        this.rootNode.updateChildrenRecursive(animate)
        Tab.update()
    }

    async updateNextTick()
    {
        await tick()
        this.update(false)
    }

    toJson(): TabJson
    {
        return {
            camera: this.camera.toJson(),
            rootNode: this.rootNode.toJson(),
        }
    }

    deselect()
    {
        this.selected = false
    }

    async select()
    {
        const previousTab = get(currentTab)

        if(previousTab != null)
        {
            if(previousTab != this)
            {
                previousTab.deselect()
                setCurrentTab(null!)
            }
        }

        await tick()
        this.selected = true

        this.rootNode.animateOpacityBirthRecursive()

        setCurrentTab(this)

        await this.updateNextTick()

        this.onCameraUpdate()

        if(!this.anyNodeOnScreen())
        {
            this.camera.centerToNode(this.rootNode)
        }
    }

    anyNodeOnScreen()
    {
        let onScreen = false

        this.rootNode.forThisAndEachChildRecursive(node =>
        {
            if(node.onScreen)
            {
                onScreen = true
                return ForAction.Break
            }
        })

        return onScreen
    }
    
    getDynamicIndex()
    {
        return get(tabs).indexOf(this)
    }

    static fromJson(tabJson?: TabJson, updateTree: boolean = false): Tab
    {
        if(tabJson == null)
        {
            return this.fromNodeJson()
        }

        const tab = this.fromNodeJson(tabJson.rootNode, updateTree)

        tab.camera = Camera.fromJson(tab, tabJson.camera)

        return tab
    }

    static fromNodeJson(rootNodeJson?: NodeJson, updateTree: boolean = false): Tab
    {
        let rootNode: Node

        const tab = new Tab(null!)

        if(rootNodeJson == null)
        {
            rootNode = new Node(tab, new NodeData(undefined, "New Tab"), null!)
        }
        else
        {
            rootNode = Node.fromJson(tab, rootNodeJson!, updateTree)
        }

        tab.setRootNode(rootNode)

        return tab
    }

    static update(nextTick: boolean = false)
    {
        if(nextTick)
        {
            waitTick(1, () => this.update(false))
            return
        }

        currentTab.update(tab => tab)
        tabs.update(tabs => tabs)
    }

    static async updateNextTick()
    {
        await tick()
        this.update()
    }

    //#region selection
    readonly selectedNodes: Set<Node> = new Set()
    readonly selectedNodesData: Set<NodeData> = new Set()
    readonly selectedNodesArray = $state<Node[]>([])
    readonly selectedNodesDataArray = $state<NodeData[]>([])
    lastSelectedNodes: CircularArray<Node> = new CircularArray<Node>(1000)
    lastSelectedNode: Node = null!

    getLastSelectedAliveNode()
    {
        for(let i = 0; i < this.lastSelectedNodes.length; i++)
        {
            const node = this.lastSelectedNodes.getFromNewToOld(i)!

            if(node.alive)
            {
                return node
            }

            this.lastSelectedNodes.pop()
        }

        return getLast(this.nodes)
    }

    createChildForSelectedNodes(createChildOrSibling: boolean, startEditingLastNode: boolean, doHistory: boolean = true)
    {
        return this.createChildForNodes(this.selectedNodes, createChildOrSibling, startEditingLastNode, doHistory)
    }

    createChildForNodes(nodes: Iterable<Node> | Node, createChildOrSibling: boolean, startEditingLastNode: boolean, doHistory: boolean = true)
    {
        if(nodes instanceof Node)
        {
            nodes = [nodes]
        }

        const actions: NodedAction[] = []
        const newNodes: Node[] = []

        forEachNode(nodes, node =>
        {
            const parent = createChildOrSibling ? node : node.parent
            const belowNode = createChildOrSibling ? undefined : node
            
            const result = this.createChildForNode(parent, belowNode, false)
            newNodes.push(result.targetNode)
            actions.push(result.action)
        })
        
        this.selectNodes(newNodes, true)

        if(doHistory)
        {
            addActionToHistory(actions)
        }

        if(startEditingLastNode)
        {
            waitTick(1, () => newNodes[newNodes.length - 1]?.startEditing())
        }

        return actions
    }

    createChildForNode(inParent: Node = this.getFirstSelectedNode(), belowNode?: Node, doHistory: boolean = true): TargetNodesInfo
    {
        if(inParent == null)
        {
            return null!
        }

        const realParent = inParent.mimicOf ?? inParent.identityTheftTarget ?? inParent

        const realChild = realParent.createChild(belowNode, undefined, false)
        const actions: AddNodeAction[] = []
        
        actions.push(new AddNodeAction(realParent, realChild, realChild.childIndex))

        const mimicChildren: Node[] = []

        const belowNodeIndex = belowNode?.childIndex!

        let inParentChild: Node = realChild

        const makeMimicChild = (mimicParent: Node) =>
        {
            const mimicChild = mimicParent.createMimicChild(realChild, belowNodeIndex)
            actions.push(new AddNodeAction(mimicParent, mimicChild, mimicChild.childIndex))

            if(mimicParent == inParent)
            {
                inParentChild = mimicChild
            }

            mimicChildren.push(mimicChild)
        }

        realParent.data.forEachMimicNode(makeMimicChild)
        realParent.identityTheftBy.forEach(makeMimicChild)

        if(!realParent.childrenVisible)
        {
            realParent.setChildrenVisible(true)
        }

        inParentChild.focus()

        const action = new MultiNodedAction(actions, true)
        if(doHistory)
        {
            addActionToHistory(action)
        }

        const info: TargetNodesInfo =
        {
            realNode: realChild,
            mimicNodes: mimicChildren,
            targetNode: inParentChild,
            action,
        }

        return info
    }

    deleteSelectedNodes()
    {
        if(this.selectedNodesArray.length == 0)
        {
            return
        }

        const lastNode = getLast(this.selectedNodesArray)
        const nextInKin = lastNode.getNextInKin()

        const allRelatedNodes = getAllRelatedNodes(this.selectedNodesArray)

        multiDeleteNodes(allRelatedNodes, true)

        this.deselectNodes()

        // console.log("nextInKin")
        // console.log(nextInKin)

        if(nextInKin != null)
        {
            this.selectNodes(nextInKin, false)
            nextInKin.focus()
        }
    }

    updateChildrenOfSelectedNodesParents()
    {
        updateChildrenOfNodesParents(this.selectedNodes)
    }

    forEachNode(callback: (node: Node) => void, lastNodeAction?: (lastNode: Node) => void)
    {
        forEachNode(this.nodes, callback, lastNodeAction)
    }

    forEachSelectedNode(callback: (node: Node) => void, lastNodeAction?: (lastNode: Node) => void)
    {
        forEachNode(this.selectedNodes, callback, lastNodeAction)
    }

    selectNodes(nodes: Iterable<Node> | Node, clearOld: boolean)
    {
        if(clearOld)
        {
            this.deselectNodes()
        }

        if(nodes == null)
        {
            return
        }

        if(nodes instanceof Node)
        {
            nodes.setSelected(true)
            this.selectedNodes.add(nodes)
            this.selectedNodesArray.push(nodes)
            if(!this.selectedNodesData.has(nodes.data))
            {
                this.selectedNodesData.add(nodes.data)
                this.selectedNodesDataArray.push(nodes.data)
            }
            this.lastSelectedNodes.push(nodes)
            this.lastSelectedNode = nodes
        }
        else
        {
            for(const node of nodes)
            {
                this.selectNodes(node, false)
            }
        }
    }

    deselectNodes(nodes: Iterable<Node> | Node = undefined!)
    {
        if(nodes == null)
        {
            this.deselectNodes(this.selectedNodes)
        }
        else
        {
            if(nodes instanceof Node)
            {
                // log(`Deselecting node ${nodes.id}`)
                nodes.setSelected(false)
                this.selectedNodes.delete(nodes)
                this.selectedNodesArray.splice(this.selectedNodesArray.indexOf(nodes), 1)
                if(this.selectedNodesData.has(nodes.data))
                {
                    this.selectedNodesData.delete(nodes.data)
                    this.selectedNodesDataArray.splice(this.selectedNodesDataArray.indexOf(nodes.data), 1)
                }
            }
            else
            {

                for(const node of nodes)
                {
                    this.deselectNodes(node)
                }
            }
        }
    }

    selectLastSelectedAliveNodeIfNoneSelected(): Node | null
    {
        if(this.selectedNodes.size != 0)
        {
            return null
        }

        const lastSelectedNode = this.getLastSelectedAliveNode()

        if(lastSelectedNode == null)
        {
            return null
        }

        this.selectNodes(lastSelectedNode, false)

        return lastSelectedNode
    }
    //#endregion selection

    shouldAnimate()
    {
        if(!userConfig.get("ANIMATED"))
        {
            return false
        }

        if(1000 < this.nodes.length)
        {
            return false
        }

        const selectedTab = get(currentTab)

        if(selectedTab != this)
        {
            return false
        }

        return true
    }

    onCameraUpdate()
    {
        this.rootNode.forThisAndEachChildRecursive(node =>
        {
            node.updateOnScreen()

            if(!node.childrenVisible)
            {
                node.forEachChild(child =>
                {
                    child.onScreen = false
                })

                return null
            }
        })
    }

    invertSelectedNodes()
    {
        this.forEachNode(node =>
        {
            if(node.selected)
            {
                this.deselectNodes(node)
            }
            else
            {
                this.selectNodes(node, false)
            }
        })
    }

    move(iOffset: number)
    {
        tabs.update(allTabs =>
        {
            const oldIndex = allTabs.indexOf(this)

            const newIndex: number = wrapIndex(oldIndex, iOffset, allTabs.length)

            swapArrayElements(allTabs, oldIndex, newIndex)


            return allTabs
        })
    }

    getIndex(): number
    {
        return get(tabs).indexOf(this)
    }

    getSiblingTab(offset: number): Tab | null
    {
        const allTabs = get(tabs)
        const currentIndex = allTabs.indexOf(this)
        const newIndex = wrapIndex(currentIndex, offset, allTabs.length)

        if(newIndex === currentIndex)
        {
            return null
        }

        return allTabs[newIndex]
    }

    delete()
    {
        tabs.update(tabs =>
        {
            const i = tabs.indexOf(this)

            let newTab = this.getSiblingTab(1)

            addActionToHistory(new DeleteTabAction(this, i))
            tabs.splice(i, 1)

            if(newTab == null)
            {
                newTab = Tab.fromJson()
                tabs.push(newTab)
            }

            newTab.select()

            return tabs
        })
    }

    openContextMenu(x: number = pointerLast.x, y: number = pointerLast.y)
    {
        waitHack(() =>
        {
            // log("tab")
            contextMenuState.set(EMPTY_CONTEXT_MENU)
            waitTick(1, () =>
            {
                contextMenuState.set
                ({
                    type: "tab",
                    rect: new DOMRect(x, y),
                    targets: [this],
                })
            })
        })
    }

    openNodesContextMenu(x: number = pointerLast.x, y: number = pointerLast.y)
    {
        contextMenuState.set(EMPTY_CONTEXT_MENU)
        waitTick(1, () =>
        {
            contextMenuState.set
            ({
                type: "node",
                rect: new DOMRect(x, y),
                targets: this.selectedNodesArray,
            })
        })
    }

    copySelectedNodesToClipboard(deleteAfter: boolean = false, asJsonOrText: boolean)
    {
        const tab = get(currentTab)
            
        const selectedNodesArray = tab.selectedNodesArray

        if(asJsonOrText)
        {
            setClipboard(selectedNodesArray.map(node => node.toJson()))
        }
        else
        {
            const text = selectedNodesArray.map(node => node.toText(true)).join("\n")
            setClipboardTextOnly(text)
        }

        if(clipboard.length > 0)
        {
            if(navigatorSupportsClipboard())
            {
                navigator.clipboard.writeText(clipboard)
            }
        }

        if(deleteAfter)
        {
            multiDeleteNodes(tab.selectedNodes, true)
        }
    }

    async pasteFromClipboard()
    {
        const tab = get(currentTab)

        if(tab.selectedNodes.size == 0)
        {
            messages.addMessage(`No node selected to paste into!\nSelect a node and press Ctrl + V to paste!`)
            return
        }

        messages.addMessage(`Pasting nodes...`)

        let didSomethingWithClipboard = false

        if(navigatorSupportsClipboard())
        {
            const items = await navigator.clipboard.read()
        
            for (const item of items)
            {
                // if(item.types.includes("image/png"))
                // {
                //     const blob = await item.getType("image/png")
        
                //     const url = URL.createObjectURL(blob)
        
                //     console.log(url)
                // }
                // else
        
                if(item.types.includes("text/plain"))
                {
                    const text = await item.getType("text/plain")
                    const textData = await text.text()
        
                    let jsonSuccess = false
        
                    try
                    {
                        let parsedJson = JSON.parse(textData)
            
                        if(parsedJson != null)
                        {
                            if(!Array.isArray(parsedJson))
                            {
                                parsedJson = [parsedJson]
                            }
        
                            if(parsedJson.length > 0)
                            {
                                if("text" in parsedJson[0])
                                {
                                    const rootNodes = this.pasteFromJsonArray(parsedJson)
        
                                    if(rootNodes.length > 0)
                                    {
                                        jsonSuccess = true
                                    }
                                }
                            }
                        }
                    }
                    catch(e)
                    {
                    }
        
                    if(jsonSuccess)
                    {
                        didSomethingWithClipboard = true
                    }
                    else
                    {
                        tab.forEachSelectedNode(node =>
                        {
                            console.log(`Pasting text into node ${node.id} from clipboard:`)
                            const rootNodes = Node.fromText(get(currentTab), textData)
                            const actions: NodedAction[] = []
            
                            for(const rootNode of rootNodes)
                            {
                                console.log(rootNode.toText(false))
                                rootNode.attachToParent(node)
                                actions.push(new AddNodeAction(node, rootNode, rootNode.childIndex, true))
                            }
        
                            if(rootNodes.length > 0)
                            {
                                addActionToHistory(actions)
                                didSomethingWithClipboard = true
                            }
                        })
                    }
                }
            }
        }
        
        if(!didSomethingWithClipboard)
        {
            const rootNodes = this.pasteFromJsonArray()

            if(rootNodes.length > 0)
            {
                didSomethingWithClipboard = true
            }
        }

        if(didSomethingWithClipboard)
        {
            messages.addSuccessMessage(`Finished pasting from clipboard!`)
            tab.update(true)
        }
        else
        {
            messages.addWarningMessage(`No nodes to paste!\nCopy/Cut nodes first`)
        }
    }

    pasteFromJsonArray(jsonNodesArray: any[] = jsonNodesClipboard): Node[]
    {
        if(jsonNodesArray == null)
        {
            return []
        }

        const tab = get(currentTab)
        
        const rootNodes: Node[] = []

        const actions: NodedAction[] = []

        const nodesToPasteTo = [...tab.selectedNodes]

        for(const node of nodesToPasteTo)
        {
            rootNodes.push(node.rootNode)
            const children = node.createChildrenFromJsonRecursive(jsonNodesArray)
            const firstLayer = children.get(0)

            if(firstLayer != null)
            {
                for(const firstLayerChild of firstLayer)
                {
                    actions.push(new AddNodeAction(node, firstLayerChild, firstLayerChild.childIndex, true))
                }
            }
        }

        addActionToHistory(actions)

        // for(const rootNode of rootNodes)
        // {
        //     rootNode.updateTreeRecursive()
        // }

        return rootNodes
    }
}
//region Tab class end

export function updateChildrenOfNodesParents(nodes: Iterable<Node>)
{
    const parents: Set<Node> = new Set()

    for(const node of nodes)
    {
        if(node.parent == null)
        {
            continue
        }

        parents.add(node.parent)
    }

    for(const parent of parents)
    {
        parent.updateChildren()
    }
}

export function forEveryTab(callback: (tab: Tab) => void | boolean)
{
    forEach(get(tabs), tab => { return callback(tab) })
}

export function forEveryNode(callback: (node: Node) => void | boolean, createCopy: boolean = false)
{
    for(const tab of get(tabs))
    {
        forEachNode(tab.nodes, callback, undefined, createCopy)
    }
}

export function forEachNodeData(callback: (data: NodeData) => void | boolean)
{
    for(const data of nodesDataMap.values())
    {
        const result = callback(data)

        if(result === true)
        {
            return
        }
    }
}

export function getNodesData(filter: (data: NodeData) => boolean = null!): NodeData[]
{
    const nodes: NodeData[] = []

    forEachNodeData(data =>
    {
        if(filter == null || filter(data))
        {
            nodes.push(data)
        }
    })

    return nodes
}

export function getNodes(filter: (node: Node) => boolean = null!): Node[]
{
    const nodes: Node[] = []

    forEveryNode(node =>
    {
        if(filter == null || filter(node))
        {
            nodes.push(node)
        }
    }, false)

    return nodes
}

export function findFirstNode(filter: (node: Node) => boolean): Node
{
    let foundNode: Node = null!

    forEveryNode(node =>
    {
        if(filter(node))
        {
            foundNode = node
            return true
        }
    }, false)

    return foundNode
}